#include "biblia.h"

void Biblia::CarregarProverbios(Biblia* b) {
    b->dados[PROVERBIOS].nome = _("Proverbios");

    b->dados[PROVERBIOS].capitulos[1].versos[1] = _("Provérbios de Salomão, filho de Davi, rei de Israel:");
    b->dados[PROVERBIOS].capitulos[1].versos[2] = _("Para se conhecer a sabedoria e a instrução; para se entenderem as palavras de inteligência;");
    b->dados[PROVERBIOS].capitulos[1].versos[3] = _("para se instruir em sábio procedimento, em retidão, justiça e eqüidade;");
    b->dados[PROVERBIOS].capitulos[1].versos[4] = _("para se dar aos simples prudência, e aos jovens conhecimento e bom siso.");
    b->dados[PROVERBIOS].capitulos[1].versos[5] = _("Ouça também, o sábio e cresça em ciência, e o entendido adquira habilidade,");
    b->dados[PROVERBIOS].capitulos[1].versos[6] = _("para entender provérbios e parábolas, as palavras dos sábios, e seus enigmas.");
    b->dados[PROVERBIOS].capitulos[1].versos[7] = _("O temor do Senhor é o princípio do conhecimento; mas os insensatos desprezam a sabedoria e a instrução.");
    b->dados[PROVERBIOS].capitulos[1].versos[8] = _("Filho meu, ouve a instrução de teu pai, e não deixes o ensino de tua mãe.");
    b->dados[PROVERBIOS].capitulos[1].versos[9] = _("Porque eles serão uma grinalda de graça para a tua cabeça, e colares para o teu pescoço.");
    b->dados[PROVERBIOS].capitulos[1].versos[10] = _("Filho meu, se os pecadores te quiserem seduzir, não consintas.");
    b->dados[PROVERBIOS].capitulos[1].versos[11] = _("Se disserem: Vem conosco; embosquemo-nos para derramar sangue; espreitemos sem razão o inocente;");
    b->dados[PROVERBIOS].capitulos[1].versos[12] = _("traguemo-los vivos, como o Seol, e inteiros como os que descem à cova;");
    b->dados[PROVERBIOS].capitulos[1].versos[13] = _("acharemos toda sorte de bens preciosos; encheremos as nossas casas de despojos;");
    b->dados[PROVERBIOS].capitulos[1].versos[14] = _("lançarás a tua sorte entre nós; teremos todos uma só bolsa;");
    b->dados[PROVERBIOS].capitulos[1].versos[15] = _("filho meu, não andes no caminho com eles; guarda da sua vereda o teu pé,");
    b->dados[PROVERBIOS].capitulos[1].versos[16] = _("porque os seus pés correm para o mal, e eles se apressam a derramar sangue.");
    b->dados[PROVERBIOS].capitulos[1].versos[17] = _("Pois debalde se estende a rede à vista de qualquer ave.");
    b->dados[PROVERBIOS].capitulos[1].versos[18] = _("Mas estes se põem em emboscadas contra o seu próprio sangue, e as suas próprias vidas espreitam.");
    b->dados[PROVERBIOS].capitulos[1].versos[19] = _("Tais são as veredas de todo aquele que se entrega à cobiça; ela tira a vida dos que a possuem.");
    b->dados[PROVERBIOS].capitulos[1].versos[20] = _("A suprema sabedoria altissonantemente clama nas ruas; nas praças levanta a sua voz.");
    b->dados[PROVERBIOS].capitulos[1].versos[21] = _("Do alto dos muros clama; às entradas das portas e na cidade profere as suas palavras:");
    b->dados[PROVERBIOS].capitulos[1].versos[22] = _("Até quando, ó estúpidos, amareis a estupidez? e até quando se deleitarão no escárnio os escarnecedores, e odiarão os insensatos o conhecimento?");
    b->dados[PROVERBIOS].capitulos[1].versos[23] = _("Convertei-vos pela minha repreensão; eis que derramarei sobre vós o meu; espírito e vos farei saber as minhas palavras.");
    b->dados[PROVERBIOS].capitulos[1].versos[24] = _("Mas, porque clamei, e vós recusastes; porque estendi a minha mão, e não houve quem desse atenção;");
    b->dados[PROVERBIOS].capitulos[1].versos[25] = _("antes desprezastes todo o meu conselho, e não fizestes caso da minha repreensão;");
    b->dados[PROVERBIOS].capitulos[1].versos[26] = _("também eu me rirei no dia da vossa calamidade; zombarei, quando sobrevier o vosso terror,");
    b->dados[PROVERBIOS].capitulos[1].versos[27] = _("quando o terror vos sobrevier como tempestade, e a vossa calamidade passar como redemoinho, e quando vos sobrevierem aperto e angústia.");
    b->dados[PROVERBIOS].capitulos[1].versos[28] = _("Então a mim clamarão, mas eu não responderei; diligentemente me buscarão, mas não me acharão.");
    b->dados[PROVERBIOS].capitulos[1].versos[29] = _("Porquanto aborreceram o conhecimento, e não preferiram o temor do Senhor;");
    b->dados[PROVERBIOS].capitulos[1].versos[30] = _("não quiseram o meu conselho e desprezaram toda a minha repreensão;");
    b->dados[PROVERBIOS].capitulos[1].versos[31] = _("portanto comerão do fruto do seu caminho e se fartarão dos seus próprios conselhos.");
    b->dados[PROVERBIOS].capitulos[1].versos[32] = _("Porque o desvio dos néscios os matará, e a prosperidade dos loucos os destruirá.");
    b->dados[PROVERBIOS].capitulos[1].versos[33] = _("Mas o que me der ouvidos habitará em segurança, e estará tranqüilo, sem receio do mal.");

    b->dados[PROVERBIOS].capitulos[2].versos[1] = _("Filho meu, se aceitares as minhas palavras, e entesourares contigo os meus mandamentos,");
    b->dados[PROVERBIOS].capitulos[2].versos[2] = _("para fazeres atento à sabedoria o teu ouvido, e para inclinares o teu coração ao entendimento;");
    b->dados[PROVERBIOS].capitulos[2].versos[3] = _("sim, se clamares por discernimento, e por entendimento alçares a tua voz;");
    b->dados[PROVERBIOS].capitulos[2].versos[4] = _("se o buscares como a prata e o procurares como a tesouros escondidos;");
    b->dados[PROVERBIOS].capitulos[2].versos[5] = _("então entenderás o temor do Senhor, e acharás o conhecimento de Deus.");
    b->dados[PROVERBIOS].capitulos[2].versos[6] = _("Porque o Senhor dá a sabedoria; da sua boca procedem o conhecimento e o entendimento;");
    b->dados[PROVERBIOS].capitulos[2].versos[7] = _("ele reserva a verdadeira sabedoria para os retos; e escudo para os que caminham em integridade,");
    b->dados[PROVERBIOS].capitulos[2].versos[8] = _("guardando-lhes as veredas da justiça, e preservando o caminho dos seus santos.");
    b->dados[PROVERBIOS].capitulos[2].versos[9] = _("Então entenderás a retidão, a justiça, a eqüidade, e todas as boas veredas.");
    b->dados[PROVERBIOS].capitulos[2].versos[10] = _("Pois a sabedoria entrará no teu coração, e o conhecimento será aprazível à tua alma;");
    b->dados[PROVERBIOS].capitulos[2].versos[11] = _("o bom siso te protegerá, e o discernimento e guardará;");
    b->dados[PROVERBIOS].capitulos[2].versos[12] = _("para te livrar do mau caminho, e do homem que diz coisas perversas;");
    b->dados[PROVERBIOS].capitulos[2].versos[13] = _("dos que deixam as veredas da retidão, para andarem pelos caminhos das trevas;");
    b->dados[PROVERBIOS].capitulos[2].versos[14] = _("que se alegram de fazer o mal, e se deleitam nas perversidades dos maus;");
    b->dados[PROVERBIOS].capitulos[2].versos[15] = _("dos que são tortuosos nas suas veredas; e iníquos nas suas carreiras;");
    b->dados[PROVERBIOS].capitulos[2].versos[16] = _("e para te livrar da mulher estranha, da estrangeira que lisonjeia com suas palavras;");
    b->dados[PROVERBIOS].capitulos[2].versos[17] = _("a qual abandona o companheiro da sua mocidade e se esquece do concerto do seu Deus;");
    b->dados[PROVERBIOS].capitulos[2].versos[18] = _("pois a sua casa se inclina para a morte, e as suas veredas para as sombras.");
    b->dados[PROVERBIOS].capitulos[2].versos[19] = _("Nenhum dos que se dirigirem a ela, tornara a sair, nem retomará as veredas da vida.");
    b->dados[PROVERBIOS].capitulos[2].versos[20] = _("Assim andarás pelo caminho dos bons, e guardarás as veredas dos justos.");
    b->dados[PROVERBIOS].capitulos[2].versos[21] = _("Porque os retos habitarão a terra, e os íntegros permanecerão nela.");
    b->dados[PROVERBIOS].capitulos[2].versos[22] = _("Mas os ímpios serão exterminados da terra, e dela os aleivosos serão desarraigados.");

    b->dados[PROVERBIOS].capitulos[3].versos[1] = _("Filho meu, não te esqueças da minha instrução, e o teu coração guarde os meus mandamentos;");
    b->dados[PROVERBIOS].capitulos[3].versos[2] = _("porque eles te darão longura de dias, e anos de vida e paz.");
    b->dados[PROVERBIOS].capitulos[3].versos[3] = _("Não se afastem de ti a benignidade e a fidelidade; ata-as ao teu pescoço, escreve-as na tábua do teu coração;");
    b->dados[PROVERBIOS].capitulos[3].versos[4] = _("assim acharás favor e bom entendimento à vista de Deus e dos homens.");
    b->dados[PROVERBIOS].capitulos[3].versos[5] = _("Confia no Senhor de todo o teu coração, e não te estribes no teu próprio entendimento.");
    b->dados[PROVERBIOS].capitulos[3].versos[6] = _("Reconhece-o em todos os teus caminhos, e ele endireitará as tuas veredas.");
    b->dados[PROVERBIOS].capitulos[3].versos[7] = _("Não sejas sábio a teus próprios olhos; teme ao Senhor e aparta-te do mal.");
    b->dados[PROVERBIOS].capitulos[3].versos[8] = _("Isso será saúde para a tua carne; e refrigério para os teus ossos.");
    b->dados[PROVERBIOS].capitulos[3].versos[9] = _("Honra ao Senhor com os teus bens, e com as primícias de toda a tua renda;");
    b->dados[PROVERBIOS].capitulos[3].versos[10] = _("assim se encherão de fartura os teus celeiros, e trasbordarão de mosto os teus lagares.");
    b->dados[PROVERBIOS].capitulos[3].versos[11] = _("Filho meu, não rejeites a disciplina do Senhor, nem te enojes da sua repreensão;");
    b->dados[PROVERBIOS].capitulos[3].versos[12] = _("porque o Senhor repreende aquele a quem ama, assim como o pai ao filho a quem quer bem.");
    b->dados[PROVERBIOS].capitulos[3].versos[13] = _("Feliz é o homem que acha sabedoria, e o homem que adquire entendimento;");
    b->dados[PROVERBIOS].capitulos[3].versos[14] = _("pois melhor é o lucro que ela dá do que o lucro da prata, e a sua renda do que o ouro.");
    b->dados[PROVERBIOS].capitulos[3].versos[15] = _("Mais preciosa é do que as jóias, e nada do que possas desejar é comparável a ela.");
    b->dados[PROVERBIOS].capitulos[3].versos[16] = _("Longura de dias há na sua mão direita; na sua esquerda riquezas e honra.");
    b->dados[PROVERBIOS].capitulos[3].versos[17] = _("Os seus caminhos são caminhos de delícias, e todas as suas veredas são paz.");
    b->dados[PROVERBIOS].capitulos[3].versos[18] = _("É árvore da vida para os que dela lançam mão, e bem-aventurado é todo aquele que a retém.");
    b->dados[PROVERBIOS].capitulos[3].versos[19] = _("O Senhor pela sabedoria fundou a terra; pelo entendimento estabeleceu o céu.");
    b->dados[PROVERBIOS].capitulos[3].versos[20] = _("Pelo seu conhecimento se fendem os abismos, e as nuvens destilam o orvalho.");
    b->dados[PROVERBIOS].capitulos[3].versos[21] = _("Filho meu, não se apartem estas coisas dos teus olhos: guarda a verdadeira sabedoria e o bom siso;");
    b->dados[PROVERBIOS].capitulos[3].versos[22] = _("assim serão elas vida para a tua alma, e adorno para o teu pescoço.");
    b->dados[PROVERBIOS].capitulos[3].versos[23] = _("Então andarás seguro pelo teu caminho, e não tropeçará o teu pé.");
    b->dados[PROVERBIOS].capitulos[3].versos[24] = _("Quando te deitares, não temerás; sim, tu te deitarás e o teu sono será suave.");
    b->dados[PROVERBIOS].capitulos[3].versos[25] = _("Não temas o pavor repentino, nem a assolação dos ímpios quando vier.");
    b->dados[PROVERBIOS].capitulos[3].versos[26] = _("Porque o Senhor será a tua confiança, e guardará os teus pés de serem presos.");
    b->dados[PROVERBIOS].capitulos[3].versos[27] = _("Não negues o bem a quem de direito, estando no teu poder fazê-lo.");
    b->dados[PROVERBIOS].capitulos[3].versos[28] = _("Não digas ao teu próximo: Vai, e volta, amanhã to darei; tendo-o tu contigo.");
    b->dados[PROVERBIOS].capitulos[3].versos[29] = _("Não maquines o mal contra o teu próximo, que habita contigo confiadamente.");
    b->dados[PROVERBIOS].capitulos[3].versos[30] = _("Não contendas com um homem, sem motivo, não te havendo ele feito o mal.");
    b->dados[PROVERBIOS].capitulos[3].versos[31] = _("Não tenhas inveja do homem violento, nem escolhas nenhum de seus caminhos.");
    b->dados[PROVERBIOS].capitulos[3].versos[32] = _("Porque o perverso é abominação para o Senhor, mas com os retos está o seu segredo.");
    b->dados[PROVERBIOS].capitulos[3].versos[33] = _("A maldição do Senhor habita na casa do ímpio, mas ele abençoa a habitação dos justos.");
    b->dados[PROVERBIOS].capitulos[3].versos[34] = _("Ele escarnece dos escarnecedores, mas dá graça aos humildes.");
    b->dados[PROVERBIOS].capitulos[3].versos[35] = _("Os sábios herdarão honra, mas a exaltação dos loucos se converte em ignomínia.");

    b->dados[PROVERBIOS].capitulos[4].versos[1] = _("Ouvi, filhos, a instrução do pai, e estai atentos para conhecerdes o entendimento.");
    b->dados[PROVERBIOS].capitulos[4].versos[2] = _("Pois eu vos dou boa doutrina; não abandoneis o meu ensino.");
    b->dados[PROVERBIOS].capitulos[4].versos[3] = _("Quando eu era filho aos pés de meu, pai, tenro e único em estima diante de minha mãe,");
    b->dados[PROVERBIOS].capitulos[4].versos[4] = _("ele me ensinava, e me dizia: Retenha o teu coração as minhas palavras; guarda os meus mandamentos, e vive.");
    b->dados[PROVERBIOS].capitulos[4].versos[5] = _("Adquire a sabedoria, adquire o entendimento; não te esqueças nem te desvies das palavras da minha boca.");
    b->dados[PROVERBIOS].capitulos[4].versos[6] = _("Não a abandones, e ela te guardará; ama-a, e ela te preservará.");
    b->dados[PROVERBIOS].capitulos[4].versos[7] = _("A sabedoria é a coisa principal; adquire, pois, a sabedoria; sim, com tudo o que possuis adquire o entendimento.");
    b->dados[PROVERBIOS].capitulos[4].versos[8] = _("Estima-a, e ela te exaltará; se a abraçares, ela te honrará.");
    b->dados[PROVERBIOS].capitulos[4].versos[9] = _("Ela dará à tua cabeça uma grinalda de graça; e uma coroa de glória te entregará.");
    b->dados[PROVERBIOS].capitulos[4].versos[10] = _("Ouve, filho meu, e aceita as minhas palavras, para que se multipliquem os anos da tua vida.");
    b->dados[PROVERBIOS].capitulos[4].versos[11] = _("Eu te ensinei o caminho da sabedoria; guiei-te pelas veredas da retidão.");
    b->dados[PROVERBIOS].capitulos[4].versos[12] = _("Quando andares, não se embaraçarão os teus passos; e se correres, não tropeçarás.");
    b->dados[PROVERBIOS].capitulos[4].versos[13] = _("Apega-te à instrução e não a largues; guarda-a, porque ela é a tua vida.");
    b->dados[PROVERBIOS].capitulos[4].versos[14] = _("Não entres na vereda dos ímpios, nem andes pelo caminho dos maus.");
    b->dados[PROVERBIOS].capitulos[4].versos[15] = _("Evita-o, não passes por ele; desvia-te dele e passa de largo.");
    b->dados[PROVERBIOS].capitulos[4].versos[16] = _("Pois não dormem, se não fizerem o mal, e foge deles o sono se não fizerem tropeçar alguém.");
    b->dados[PROVERBIOS].capitulos[4].versos[17] = _("Porque comem o pão da impiedade, e bebem o vinho da violência.");
    b->dados[PROVERBIOS].capitulos[4].versos[18] = _("Mas a vereda dos justos é como a luz da aurora que vai brilhando mais e mais até ser dia perfeito.");
    b->dados[PROVERBIOS].capitulos[4].versos[19] = _("O caminho dos ímpios é como a escuridão: não sabem eles em que tropeçam.");
    b->dados[PROVERBIOS].capitulos[4].versos[20] = _("Filho meu, atenta para as minhas palavras; inclina o teu ouvido às minhas instruções.");
    b->dados[PROVERBIOS].capitulos[4].versos[21] = _("Não se apartem elas de diante dos teus olhos; guarda-as dentro do teu coração.");
    b->dados[PROVERBIOS].capitulos[4].versos[22] = _("Porque são vida para os que as encontram, e saúde para todo o seu corpo.");
    b->dados[PROVERBIOS].capitulos[4].versos[23] = _("Guarda com toda a diligência o teu coração, porque dele procedem as fontes da vida.");
    b->dados[PROVERBIOS].capitulos[4].versos[24] = _("Desvia de ti a malignidade da boca, e alonga de ti a perversidade dos lábios.");
    b->dados[PROVERBIOS].capitulos[4].versos[25] = _("Dirijam-se os teus olhos para a frente, e olhem as tuas pálpebras diretamente diante de ti.");
    b->dados[PROVERBIOS].capitulos[4].versos[26] = _("Pondera a vereda de teus pés, e serão seguros todos os teus caminhos.");
    b->dados[PROVERBIOS].capitulos[4].versos[27] = _("Não declines nem para a direita nem para a esquerda; retira o teu pé do mal.");

    b->dados[PROVERBIOS].capitulos[5].versos[1] = _("Filho meu, atende à minha sabedoria; inclinam teu ouvido à minha prudência;");
    b->dados[PROVERBIOS].capitulos[5].versos[2] = _("para que observes a discrição, e os teus lábios guardem o conhecimento.");
    b->dados[PROVERBIOS].capitulos[5].versos[3] = _("Porque os lábios da mulher licenciosa destilam mel, e a sua boca e mais macia do que o azeite;");
    b->dados[PROVERBIOS].capitulos[5].versos[4] = _("mas o seu fim é amargoso como o absinto, agudo como a espada de dois gumes.");
    b->dados[PROVERBIOS].capitulos[5].versos[5] = _("Os seus pés descem à morte; os seus passos seguem no caminho do Seol.");
    b->dados[PROVERBIOS].capitulos[5].versos[6] = _("Ela não pondera a vereda da vida; incertos são os seus caminhos, e ela o ignora.");
    b->dados[PROVERBIOS].capitulos[5].versos[7] = _("Agora, pois, filhos, dai-me ouvidos, e não vos desvieis das palavras da minha boca.");
    b->dados[PROVERBIOS].capitulos[5].versos[8] = _("Afasta para longe dela o teu caminho, e não te aproximes da porta da sua casa;");
    b->dados[PROVERBIOS].capitulos[5].versos[9] = _("para que não dês a outros a tua honra, nem os teus anos a cruéis;");
    b->dados[PROVERBIOS].capitulos[5].versos[10] = _("para que não se fartem os estranhos dos teus bens, e não entrem os teus trabalhos na casa do estrangeiro,");
    b->dados[PROVERBIOS].capitulos[5].versos[11] = _("e gemas no teu fim, quando se consumirem a tua carne e o teu corpo,");
    b->dados[PROVERBIOS].capitulos[5].versos[12] = _("e digas: Como detestei a disciplina! e desprezou o meu coração a repreensão!");
    b->dados[PROVERBIOS].capitulos[5].versos[13] = _("e não escutei a voz dos que me ensinavam, nem aos que me instruíam inclinei o meu ouvido!");
    b->dados[PROVERBIOS].capitulos[5].versos[14] = _("Quase cheguei à ruína completa, no meio da congregação e da assembléia.");
    b->dados[PROVERBIOS].capitulos[5].versos[15] = _("Bebe a água da tua própria cisterna, e das correntes do teu poço.");
    b->dados[PROVERBIOS].capitulos[5].versos[16] = _("Derramar-se-iam as tuas fontes para fora, e pelas ruas os ribeiros de águas?");
    b->dados[PROVERBIOS].capitulos[5].versos[17] = _("Sejam para ti só, e não para os estranhos juntamente contigo.");
    b->dados[PROVERBIOS].capitulos[5].versos[18] = _("Seja bendito o teu manancial; e regozija-te na mulher da tua mocidade.");
    b->dados[PROVERBIOS].capitulos[5].versos[19] = _("Como corça amorosa, e graciosa cabra montesa saciem-te os seus seios em todo o tempo; e pelo seu amor sê encantado perpetuamente.");
    b->dados[PROVERBIOS].capitulos[5].versos[20] = _("E por que, filho meu, andarias atraído pela mulher licenciosa, e abraçarias o seio da adúltera?");
    b->dados[PROVERBIOS].capitulos[5].versos[21] = _("Porque os caminhos do homem estão diante dos olhos do Senhor, o qual observa todas as suas veredas.");
    b->dados[PROVERBIOS].capitulos[5].versos[22] = _("Quanto ao ímpio, as suas próprias iniqüidades o prenderão, e pelas cordas do seu pecado será detido.");
    b->dados[PROVERBIOS].capitulos[5].versos[23] = _("Ele morre pela falta de disciplina; e pelo excesso da sua loucura anda errado.");

    b->dados[PROVERBIOS].capitulos[6].versos[1] = _("Filho meu, se ficaste por fiador do teu próximo, se te empenhaste por um estranho,");
    b->dados[PROVERBIOS].capitulos[6].versos[2] = _("estás enredado pelos teus lábios; estás preso pelas palavras da tua boca.");
    b->dados[PROVERBIOS].capitulos[6].versos[3] = _("Faze pois isto agora, filho meu, e livra-te, pois já caíste nas mãos do teu próximo; vai, humilha-te, e importuna o teu próximo;");
    b->dados[PROVERBIOS].capitulos[6].versos[4] = _("não dês sono aos teus olhos, nem adormecimento às tuas pálpebras;");
    b->dados[PROVERBIOS].capitulos[6].versos[5] = _("livra-te como a gazela da mão do caçador, e como a ave da mão do passarinheiro.");
    b->dados[PROVERBIOS].capitulos[6].versos[6] = _("Vai ter com a formiga, ó preguiçoso, considera os seus caminhos, e sê sábio;");
    b->dados[PROVERBIOS].capitulos[6].versos[7] = _("a qual, não tendo chefe, nem superintendente, nem governador,");
    b->dados[PROVERBIOS].capitulos[6].versos[8] = _("no verão faz a provisão do seu mantimento, e ajunta o seu alimento no tempo da ceifa.");
    b->dados[PROVERBIOS].capitulos[6].versos[9] = _("o preguiçoso, até quando ficarás deitador? quando te levantarás do teu sono?");
    b->dados[PROVERBIOS].capitulos[6].versos[10] = _("um pouco para dormir, um pouco para toscanejar, um pouco para cruzar as mãos em repouso;");
    b->dados[PROVERBIOS].capitulos[6].versos[11] = _("assim te sobrevirá a tua pobreza como um ladrão, e a tua necessidade como um homem armado.");
    b->dados[PROVERBIOS].capitulos[6].versos[12] = _("O homem vil, o homem iníquo, anda com a perversidade na boca,");
    b->dados[PROVERBIOS].capitulos[6].versos[13] = _("pisca os olhos, faz sinais com os pés, e acena com os dedos;");
    b->dados[PROVERBIOS].capitulos[6].versos[14] = _("perversidade há no seu coração; todo o tempo maquina o mal; anda semeando contendas.");
    b->dados[PROVERBIOS].capitulos[6].versos[15] = _("Pelo que a sua destruição virá repentinamente; subitamente será quebrantado, sem que haja cura.");
    b->dados[PROVERBIOS].capitulos[6].versos[16] = _("Há seis coisas que o Senhor detesta; sim, há sete que ele abomina:");
    b->dados[PROVERBIOS].capitulos[6].versos[17] = _("olhos altivos, língua mentirosa, e mãos que derramam sangue inocente;");
    b->dados[PROVERBIOS].capitulos[6].versos[18] = _("coração que maquina projetos iníquos, pés que se apressam a correr para o mal;");
    b->dados[PROVERBIOS].capitulos[6].versos[19] = _("testemunha falsa que profere mentiras, e o que semeia contendas entre irmãos.");
    b->dados[PROVERBIOS].capitulos[6].versos[20] = _("Filho meu, guarda o mandamento de, teu pai, e não abandones a instrução de tua mãe;");
    b->dados[PROVERBIOS].capitulos[6].versos[21] = _("ata-os perpetuamente ao teu coração, e pendura-os ao teu pescoço.");
    b->dados[PROVERBIOS].capitulos[6].versos[22] = _("Quando caminhares, isso te guiará; quando te deitares, te guardará; quando acordares, falará contigo.");
    b->dados[PROVERBIOS].capitulos[6].versos[23] = _("Porque o mandamento é uma lâmpada, e a instrução uma luz; e as repreensões da disciplina são o caminho da vida,");
    b->dados[PROVERBIOS].capitulos[6].versos[24] = _("para te guardarem da mulher má, e das lisonjas da língua da adúltera.");
    b->dados[PROVERBIOS].capitulos[6].versos[25] = _("Não cobices no teu coração a sua formosura, nem te deixes prender pelos seus olhares.");
    b->dados[PROVERBIOS].capitulos[6].versos[26] = _("Porque o preço da prostituta é apenas um bocado de pão, mas a adúltera anda à caça da própria vida do homem.");
    b->dados[PROVERBIOS].capitulos[6].versos[27] = _("Pode alguém tomar fogo no seu seio, sem que os seus vestidos se queimem?");
    b->dados[PROVERBIOS].capitulos[6].versos[28] = _("Ou andará sobre as brasas sem que se queimem os seus pés?");
    b->dados[PROVERBIOS].capitulos[6].versos[29] = _("Assim será o que entrar à mulher do seu próximo; não ficará inocente quem a tocar.");
    b->dados[PROVERBIOS].capitulos[6].versos[30] = _("Não é desprezado o ladrão, mesmo quando furta para saciar a fome?");
    b->dados[PROVERBIOS].capitulos[6].versos[31] = _("E, se for apanhado, pagará sete vezes tanto, dando até todos os bens de sua casa.");
    b->dados[PROVERBIOS].capitulos[6].versos[32] = _("O que adultera com uma mulher é falto de entendimento; destrói-se a si mesmo, quem assim procede.");
    b->dados[PROVERBIOS].capitulos[6].versos[33] = _("Receberá feridas e ignomínia, e o seu opróbrio nunca se apagará;");
    b->dados[PROVERBIOS].capitulos[6].versos[34] = _("porque o ciúme enfurece ao marido, que de maneira nenhuma poupará no dia da vingança.");
    b->dados[PROVERBIOS].capitulos[6].versos[35] = _("Não aceitará resgate algum, nem se aplacará, ainda que multipliques os presentes.");

    b->dados[PROVERBIOS].capitulos[7].versos[1] = _("Filho meu, guarda as minhas palavras, e entesoura contigo os meus mandamentos.");
    b->dados[PROVERBIOS].capitulos[7].versos[2] = _("Observa os meus mandamentos e vive; guarda a minha lei, como a menina dos teus olhos.");
    b->dados[PROVERBIOS].capitulos[7].versos[3] = _("Ata-os aos teus dedos, escreve-os na tábua do teu coração.");
    b->dados[PROVERBIOS].capitulos[7].versos[4] = _("Dize à sabedoria: Tu és minha irmã; e chama ao entendimento teu amigo íntimo,");
    b->dados[PROVERBIOS].capitulos[7].versos[5] = _("para te guardarem da mulher alheia, da adúltera, que lisonjeia com as suas palavras.");
    b->dados[PROVERBIOS].capitulos[7].versos[6] = _("Porque da janela da minha casa, por minhas grades olhando eu,");
    b->dados[PROVERBIOS].capitulos[7].versos[7] = _("vi entre os simples, divisei entre os jovens, um mancebo falto de juízo,");
    b->dados[PROVERBIOS].capitulos[7].versos[8] = _("que passava pela rua junto à esquina da mulher adúltera e que seguia o caminho da sua casa,");
    b->dados[PROVERBIOS].capitulos[7].versos[9] = _("no crepúsculo, à tarde do dia, à noite fechada e na escuridão;");
    b->dados[PROVERBIOS].capitulos[7].versos[10] = _("e eis que uma mulher lhe saiu ao encontro, ornada à moda das prostitutas, e astuta de coração.");
    b->dados[PROVERBIOS].capitulos[7].versos[11] = _("Ela é turbulenta e obstinada; não param em casa os seus pés;");
    b->dados[PROVERBIOS].capitulos[7].versos[12] = _("ora está ela pelas ruas, ora pelas praças, espreitando por todos os cantos.");
    b->dados[PROVERBIOS].capitulos[7].versos[13] = _("Pegou dele, pois, e o beijou; e com semblante impudico lhe disse:");
    b->dados[PROVERBIOS].capitulos[7].versos[14] = _("Sacrifícios pacíficos tenho comigo; hoje paguei os meus votos.");
    b->dados[PROVERBIOS].capitulos[7].versos[15] = _("Por isso saí ao teu encontro a buscar-te diligentemente, e te achei.");
    b->dados[PROVERBIOS].capitulos[7].versos[16] = _("Já cobri a minha cama de cobertas, de colchas de linho do Egito.");
    b->dados[PROVERBIOS].capitulos[7].versos[17] = _("Já perfumei o meu leito com mirra, aloés e cinamomo.");
    b->dados[PROVERBIOS].capitulos[7].versos[18] = _("Vem, saciemo-nos de amores até pela manhã; alegremo-nos com amores.");
    b->dados[PROVERBIOS].capitulos[7].versos[19] = _("Porque meu marido não está em casa; foi fazer uma jornada ao longe;");
    b->dados[PROVERBIOS].capitulos[7].versos[20] = _("um saquitel de dinheiro levou na mão; só lá para o dia da lua cheia voltará para casa.");
    b->dados[PROVERBIOS].capitulos[7].versos[21] = _("Ela o faz ceder com a multidão das suas palavras sedutoras, com as lisonjas dos seus lábios o arrasta.");
    b->dados[PROVERBIOS].capitulos[7].versos[22] = _("Ele a segue logo, como boi que vai ao matadouro, e como o louco ao castigo das prisões;");
    b->dados[PROVERBIOS].capitulos[7].versos[23] = _("até que uma flecha lhe atravesse o fígado, como a ave que se apressa para o laço, sem saber que está armado contra a sua vida.");
    b->dados[PROVERBIOS].capitulos[7].versos[24] = _("Agora, pois, filhos, ouvi-me, e estai atentos às palavras da minha boca.");
    b->dados[PROVERBIOS].capitulos[7].versos[25] = _("Não se desvie para os seus caminhos o teu coração, e não andes perdido nas suas veredas.");
    b->dados[PROVERBIOS].capitulos[7].versos[26] = _("Porque ela a muitos tem feito cair feridos; e são muitíssimos os que por ela foram mortos.");
    b->dados[PROVERBIOS].capitulos[7].versos[27] = _("Caminho de Seol é a sua casa, o qual desce às câmaras da morte.");

    b->dados[PROVERBIOS].capitulos[8].versos[1] = _("Não clama porventura a sabedoria, e não faz o entendimento soar a sua voz?");
    b->dados[PROVERBIOS].capitulos[8].versos[2] = _("No cume das alturas, junto ao caminho, nas encruzilhadas das veredas ela se coloca.");
    b->dados[PROVERBIOS].capitulos[8].versos[3] = _("Junto às portas, à entrada da cidade, e à entrada das portas está clamando:");
    b->dados[PROVERBIOS].capitulos[8].versos[4] = _("A vós, ó homens, clamo; e a minha voz se dirige aos filhos dos homens.");
    b->dados[PROVERBIOS].capitulos[8].versos[5] = _("Aprendei, ó simples, a prudência; entendei, ó loucos, a sabedoria.");
    b->dados[PROVERBIOS].capitulos[8].versos[6] = _("Ouvi vós, porque profiro coisas excelentes; os meus lábios se abrem para a eqüidade.");
    b->dados[PROVERBIOS].capitulos[8].versos[7] = _("Porque a minha boca profere a verdade, os meus lábios abominam a impiedade.");
    b->dados[PROVERBIOS].capitulos[8].versos[8] = _("Justas são todas as palavras da minha boca; não há nelas nenhuma coisa tortuosa nem perversa.");
    b->dados[PROVERBIOS].capitulos[8].versos[9] = _("Todas elas são retas para o que bem as entende, e justas para os que acham o conhecimento.");
    b->dados[PROVERBIOS].capitulos[8].versos[10] = _("Aceitai antes a minha correção, e não a prata; e o conhecimento, antes do que o ouro escolhido.");
    b->dados[PROVERBIOS].capitulos[8].versos[11] = _("Porque melhor é a sabedoria do que as jóias; e de tudo o que se deseja nada se pode comparar com ela.");
    b->dados[PROVERBIOS].capitulos[8].versos[12] = _("Eu, a sabedoria, habito com a prudência, e possuo o conhecimento e a discrição.");
    b->dados[PROVERBIOS].capitulos[8].versos[13] = _("O temor do Senhor é odiar o mal; a soberba, e a arrogância, e o mau caminho, e a boca perversa, eu os odeio.");
    b->dados[PROVERBIOS].capitulos[8].versos[14] = _("Meu é o conselho, e a verdadeira sabedoria; eu sou o entendimento; minha é a fortaleza.");
    b->dados[PROVERBIOS].capitulos[8].versos[15] = _("Por mim reinam os reis, e os príncipes decretam o que justo.");
    b->dados[PROVERBIOS].capitulos[8].versos[16] = _("Por mim governam os príncipes e os nobres, sim, todos os juízes da terra.");
    b->dados[PROVERBIOS].capitulos[8].versos[17] = _("Eu amo aos que me amam, e os que diligentemente me buscam me acharão.");
    b->dados[PROVERBIOS].capitulos[8].versos[18] = _("Riquezas e honra estão comigo; sim, riquezas duráveis e justiça.");
    b->dados[PROVERBIOS].capitulos[8].versos[19] = _("Melhor é o meu fruto do que o ouro, sim, do que o ouro refinado; e a minha renda melhor do que a prata escolhida.");
    b->dados[PROVERBIOS].capitulos[8].versos[20] = _("Ando pelo caminho da retidão, no meio das veredas da justiça,");
    b->dados[PROVERBIOS].capitulos[8].versos[21] = _("dotando de bens permanentes os que me amam, e enchendo os seus tesouros.");
    b->dados[PROVERBIOS].capitulos[8].versos[22] = _("O Senhor me criou como a primeira das suas obras, o princípio dos seus feitos mais antigos.");
    b->dados[PROVERBIOS].capitulos[8].versos[23] = _("Desde a eternidade fui constituída, desde o princípio, antes de existir a terra.");
    b->dados[PROVERBIOS].capitulos[8].versos[24] = _("Antes de haver abismos, fui gerada, e antes ainda de haver fontes cheias d'água.");
    b->dados[PROVERBIOS].capitulos[8].versos[25] = _("Antes que os montes fossem firmados, antes dos outeiros eu nasci,");
    b->dados[PROVERBIOS].capitulos[8].versos[26] = _("quando ele ainda não tinha feito a terra com seus campos, nem sequer o princípio do pó do mundo.");
    b->dados[PROVERBIOS].capitulos[8].versos[27] = _("Quando ele preparava os céus, aí estava eu; quando traçava um círculo sobre a face do abismo,");
    b->dados[PROVERBIOS].capitulos[8].versos[28] = _("quando estabelecia o firmamento em cima, quando se firmavam as fontes do abismo,");
    b->dados[PROVERBIOS].capitulos[8].versos[29] = _("quando ele fixava ao mar o seu termo, para que as águas não traspassassem o seu mando, quando traçava os fundamentos da terra,");
    b->dados[PROVERBIOS].capitulos[8].versos[30] = _("então eu estava ao seu lado como arquiteto; e era cada dia as suas delícias, alegrando-me perante ele em todo o tempo;");
    b->dados[PROVERBIOS].capitulos[8].versos[31] = _("folgando no seu mundo habitável, e achando as minhas delícias com os filhos dos homens.");
    b->dados[PROVERBIOS].capitulos[8].versos[32] = _("Agora, pois, filhos, ouvi-me; porque felizes são os que guardam os meus caminhos.");
    b->dados[PROVERBIOS].capitulos[8].versos[33] = _("Ouvi a correção, e sede sábios; e não a rejeiteis.");
    b->dados[PROVERBIOS].capitulos[8].versos[34] = _("Feliz é o homem que me dá ouvidos, velando cada dia às minhas entradas, esperando junto às ombreiras da minha porta.");
    b->dados[PROVERBIOS].capitulos[8].versos[35] = _("Porque o que me achar achará a vida, e alcançará o favor do Senhor.");
    b->dados[PROVERBIOS].capitulos[8].versos[36] = _("Mas o que pecar contra mim fará mal à sua própria alma; todos os que me odeiam amam a morte.");

    b->dados[PROVERBIOS].capitulos[9].versos[1] = _("A sabedoria já edificou a sua casa, já lavrou as suas sete colunas;");
    b->dados[PROVERBIOS].capitulos[9].versos[2] = _("já imolou as suas vítimas, misturou o seu vinho, e preparou a sua mesa.");
    b->dados[PROVERBIOS].capitulos[9].versos[3] = _("Já enviou as suas criadas a clamar sobre as alturas da cidade, dizendo:");
    b->dados[PROVERBIOS].capitulos[9].versos[4] = _("Quem é simples, volte-se para cá. Aos faltos de entendimento diz:");
    b->dados[PROVERBIOS].capitulos[9].versos[5] = _("Vinde, comei do meu pão, e bebei do vinho que tenho misturado.");
    b->dados[PROVERBIOS].capitulos[9].versos[6] = _("Deixai a insensatez, e vivei; e andai pelo caminho do entendimento.");
    b->dados[PROVERBIOS].capitulos[9].versos[7] = _("O que repreende ao escarnecedor, traz afronta sobre si; e o que censura ao ímpio, recebe a sua mancha.");
    b->dados[PROVERBIOS].capitulos[9].versos[8] = _("Não repreendas ao escarnecedor, para que não te odeie; repreende ao sábio, e amar-te-á.");
    b->dados[PROVERBIOS].capitulos[9].versos[9] = _("Instrui ao sábio, e ele se fará mais, sábio; ensina ao justo, e ele crescerá em entendimento.");
    b->dados[PROVERBIOS].capitulos[9].versos[10] = _("O temor do Senhor é o princípio sabedoria; e o conhecimento do Santo é o entendimento.");
    b->dados[PROVERBIOS].capitulos[9].versos[11] = _("Porque por mim se multiplicam os teus dias, e anos de vida se te acrescentarão.");
    b->dados[PROVERBIOS].capitulos[9].versos[12] = _("Se fores sábio, para ti mesmo o serás; e, se fores escarnecedor, tu só o suportarás.");
    b->dados[PROVERBIOS].capitulos[9].versos[13] = _("A mulher tola é alvoroçadora; é insensata, e não conhece o pudor.");
    b->dados[PROVERBIOS].capitulos[9].versos[14] = _("Senta-se à porta da sua casa ou numa cadeira, nas alturas da cidade,");
    b->dados[PROVERBIOS].capitulos[9].versos[15] = _("chamando aos que passam e seguem direitos o seu caminho:");
    b->dados[PROVERBIOS].capitulos[9].versos[16] = _("Quem é simples, volte-se para cá! E aos faltos de entendimento diz:");
    b->dados[PROVERBIOS].capitulos[9].versos[17] = _("As águas roubadas são doces, e o pão comido às ocultas é agradável.");
    b->dados[PROVERBIOS].capitulos[9].versos[18] = _("Mas ele não sabe que ali estão os mortos; que os seus convidados estão nas profundezas do Seol.");

    b->dados[PROVERBIOS].capitulos[10].versos[1] = _("Provérbios de Salomão. Um filho sábio alegra a seu pai; mas um filho insensato é a tristeza de sua mãe.");
    b->dados[PROVERBIOS].capitulos[10].versos[2] = _("Os tesouros da impiedade de nada aproveitam; mas a justiça livra da morte.");
    b->dados[PROVERBIOS].capitulos[10].versos[3] = _("O Senhor não deixa o justo passar fome; mas o desejo dos ímpios ele rechaça.");
    b->dados[PROVERBIOS].capitulos[10].versos[4] = _("O que trabalha com mão remissa empobrece; mas a mão do diligente enriquece.");
    b->dados[PROVERBIOS].capitulos[10].versos[5] = _("O que ajunta no verão é filho prudente; mas o que dorme na sega é filho que envergonha.");
    b->dados[PROVERBIOS].capitulos[10].versos[6] = _("Bênçãos caem sobre a cabeça do justo; porém a boca dos ímpios esconde a violência.");
    b->dados[PROVERBIOS].capitulos[10].versos[7] = _("A memória do justo é abençoada; mas o nome dos ímpios apodrecerá.");
    b->dados[PROVERBIOS].capitulos[10].versos[8] = _("O sábio de coração aceita os mandamentos; mas o insensato palra dor cairá.");
    b->dados[PROVERBIOS].capitulos[10].versos[9] = _("Quem anda em integridade anda seguro; mas o que perverte os seus caminhos será conhecido.");
    b->dados[PROVERBIOS].capitulos[10].versos[10] = _("O que acena com os olhos dá dores; e o insensato palrador cairá.");
    b->dados[PROVERBIOS].capitulos[10].versos[11] = _("A boca do justo é manancial de vida, porém a boca dos ímpios esconde a violência.");
    b->dados[PROVERBIOS].capitulos[10].versos[12] = _("O ódio excita contendas; mas o amor cobre todas as transgressões.");
    b->dados[PROVERBIOS].capitulos[10].versos[13] = _("Nos lábios do entendido se acha a sabedoria; mas a vara é para as costas do que é falto de entendimento.");
    b->dados[PROVERBIOS].capitulos[10].versos[14] = _("Os sábios entesouram o conhecimento; porém a boca do insensato é uma destruição iminente.");
    b->dados[PROVERBIOS].capitulos[10].versos[15] = _("Os bens do rico são a sua cidade forte; a ruína dos pobres é a sua pobreza.");
    b->dados[PROVERBIOS].capitulos[10].versos[16] = _("O trabalho do justo conduz à vida; a renda do ímpio, para o pecado.");
    b->dados[PROVERBIOS].capitulos[10].versos[17] = _("O que atende à instrução está na vereda da vida; mas o que rejeita a repreensão anda errado.");
    b->dados[PROVERBIOS].capitulos[10].versos[18] = _("O que encobre o ódio tem lábios falsos; e o que espalha a calúnia é um insensato.");
    b->dados[PROVERBIOS].capitulos[10].versos[19] = _("Na multidão de palavras não falta transgressão; mas o que refreia os seus lábios é prudente.");
    b->dados[PROVERBIOS].capitulos[10].versos[20] = _("A língua do justo é prata escolhida; o coração dos ímpios é de pouco valor.");
    b->dados[PROVERBIOS].capitulos[10].versos[21] = _("Os lábios do justo apascentam a muitos; mas os insensatos, por falta de entendimento, morrem.");
    b->dados[PROVERBIOS].capitulos[10].versos[22] = _("A bênção do Senhor é que enriquece; e ele não a faz seguir de dor alguma.");
    b->dados[PROVERBIOS].capitulos[10].versos[23] = _("E um divertimento para o insensato o praticar a iniqüidade; mas a conduta sábia é o prazer do homem entendido.");
    b->dados[PROVERBIOS].capitulos[10].versos[24] = _("O que o ímpio teme, isso virá sobre ele; mas aos justos se lhes concederá o seu desejo.");
    b->dados[PROVERBIOS].capitulos[10].versos[25] = _("Como passa a tempestade, assim desaparece o ímpio; mas o justo tem fundamentos eternos.");
    b->dados[PROVERBIOS].capitulos[10].versos[26] = _("Como vinagre para os dentes, como fumaça para os olhos, assim é o preguiçoso para aqueles que o mandam.");
    b->dados[PROVERBIOS].capitulos[10].versos[27] = _("O temor do Senhor aumenta os dias; mas os anos os ímpios serão abreviados.");
    b->dados[PROVERBIOS].capitulos[10].versos[28] = _("A esperança dos justos é alegria; mas a expectação dos ímpios perecerá.");
    b->dados[PROVERBIOS].capitulos[10].versos[29] = _("O caminho do Senhor é fortaleza para os retos; mas é destruição para os que praticam a iniqüidade.");
    b->dados[PROVERBIOS].capitulos[10].versos[30] = _("O justo nunca será abalado; mas os ímpios não habitarão a terra.");
    b->dados[PROVERBIOS].capitulos[10].versos[31] = _("A boca do justo produz sabedoria; porém a língua perversa será desarraigada.");
    b->dados[PROVERBIOS].capitulos[10].versos[32] = _("Os lábios do justo sabem o que agrada; porém a boca dos ímpios fala perversidades.");

    b->dados[PROVERBIOS].capitulos[11].versos[1] = _("A balança enganosa é abominação para o Senhor; mas o peso justo é o seu prazer.");
    b->dados[PROVERBIOS].capitulos[11].versos[2] = _("Quando vem a soberba, então vem a desonra; mas com os humildes está a sabedoria.");
    b->dados[PROVERBIOS].capitulos[11].versos[3] = _("A integridade dos retos os guia; porém a perversidade dos desleais os destrói.");
    b->dados[PROVERBIOS].capitulos[11].versos[4] = _("De nada aproveitam as riquezas no dia da ira; porém a justiça livra da morte.");
    b->dados[PROVERBIOS].capitulos[11].versos[5] = _("A justiça dos perfeitos endireita o seu caminho; mas o ímpio cai pela sua impiedade.");
    b->dados[PROVERBIOS].capitulos[11].versos[6] = _("A justiça dos retos os livra; mas os traiçoeiros são apanhados nas, suas próprias cobiças.");
    b->dados[PROVERBIOS].capitulos[11].versos[7] = _("Morrendo o ímpio, perece a sua esperança; e a expectativa da iniqüidade.");
    b->dados[PROVERBIOS].capitulos[11].versos[8] = _("O justo é libertado da angústia; e o ímpio fica em seu lugar.");
    b->dados[PROVERBIOS].capitulos[11].versos[9] = _("O hipócrita com a boca arruina o seu próximo; mas os justos são libertados pelo conhecimento.");
    b->dados[PROVERBIOS].capitulos[11].versos[10] = _("Quando os justos prosperam, exulta a cidade; e quando perecem os ímpios, há júbilo.");
    b->dados[PROVERBIOS].capitulos[11].versos[11] = _("Pela bênção dos retos se exalta a cidade; mas pela boca dos ímpios é derrubada.");
    b->dados[PROVERBIOS].capitulos[11].versos[12] = _("Quem despreza o seu próximo é falto de senso; mas o homem de entendimento se cala.");
    b->dados[PROVERBIOS].capitulos[11].versos[13] = _("O que anda mexericando revela segredos; mas o fiel de espírito encobre o negócio.");
    b->dados[PROVERBIOS].capitulos[11].versos[14] = _("Quando não há sábia direção, o povo cai; mas na multidão de conselheiros há segurança.");
    b->dados[PROVERBIOS].capitulos[11].versos[15] = _("Decerto sofrerá prejuízo aquele que fica por fiador do estranho; mas o que aborrece a fiança estará seguro.");
    b->dados[PROVERBIOS].capitulos[11].versos[16] = _("A mulher aprazível obtém honra, e os homens violentos obtêm riquezas.");
    b->dados[PROVERBIOS].capitulos[11].versos[17] = _("O homem bondoso faz bem à sua, própria alma; mas o cruel faz mal a si mesmo.");
    b->dados[PROVERBIOS].capitulos[11].versos[18] = _("O ímpio recebe um salário ilusório; mas o que semeia justiça recebe galardão seguro.");
    b->dados[PROVERBIOS].capitulos[11].versos[19] = _("Quem é fiel na retidão encaminha, para a vida, e aquele que segue o mal encontra a morte.");
    b->dados[PROVERBIOS].capitulos[11].versos[20] = _("Abominação para o Senhor são os perversos de coração; mas os que são perfeitos em seu caminho são o seu deleite.");
    b->dados[PROVERBIOS].capitulos[11].versos[21] = _("Decerto o homem mau não ficará sem castigo; porém a descendência dos justos será livre.");
    b->dados[PROVERBIOS].capitulos[11].versos[22] = _("Como jóia de ouro em focinho de porca, assim é a mulher formosa que se aparta da discrição.");
    b->dados[PROVERBIOS].capitulos[11].versos[23] = _("O desejo dos justos é somente o bem; porém a expectativa dos ímpios é a ira.");
    b->dados[PROVERBIOS].capitulos[11].versos[24] = _("Um dá liberalmente, e se torna mais rico; outro retém mais do que é justo, e se empobrece.");
    b->dados[PROVERBIOS].capitulos[11].versos[25] = _("A alma generosa prosperará, e o que regar também será regado.");
    b->dados[PROVERBIOS].capitulos[11].versos[26] = _("Ao que retém o trigo o povo o amaldiçoa; mas bênção haverá sobre a cabeça do que o vende.");
    b->dados[PROVERBIOS].capitulos[11].versos[27] = _("O que busca diligentemente o bem, busca favor; mas ao que procura o mal, este lhe sobrevirá.");
    b->dados[PROVERBIOS].capitulos[11].versos[28] = _("Aquele que confia nas suas riquezas, cairá; mas os justos reverdecerão como a folhagem.");
    b->dados[PROVERBIOS].capitulos[11].versos[29] = _("O que perturba a sua casa herdará o vento; e o insensato será servo do entendido de coração.");
    b->dados[PROVERBIOS].capitulos[11].versos[30] = _("O fruto do justo é árvore de vida; e o que ganha almas sábio é.");
    b->dados[PROVERBIOS].capitulos[11].versos[31] = _("Eis que o justo é castigado na terra; quanto mais o ímpio e o pecador!");

    b->dados[PROVERBIOS].capitulos[12].versos[1] = _("O que ama a correção ama o conhecimento; mas o que aborrece a repreensão é insensato.");
    b->dados[PROVERBIOS].capitulos[12].versos[2] = _("O homem de bem alcançará o favor do Senhor; mas ao homem de perversos desígnios ele condenará.");
    b->dados[PROVERBIOS].capitulos[12].versos[3] = _("O homem não se estabelece pela impiedade; a raiz dos justos, porém, nunca será, removida.");
    b->dados[PROVERBIOS].capitulos[12].versos[4] = _("A mulher virtuosa é a coroa do seu marido; porém a que procede vergonhosamente é como apodrecimento nos seus ossos.");
    b->dados[PROVERBIOS].capitulos[12].versos[5] = _("Os pensamentos do justo são retos; mas os conselhos do ímpio são falsos.");
    b->dados[PROVERBIOS].capitulos[12].versos[6] = _("As palavras dos ímpios são emboscadas para derramarem sangue; a boca dos retos, porém, os livrará.");
    b->dados[PROVERBIOS].capitulos[12].versos[7] = _("Transtornados serão os ímpios, e não serão mais; porém a casa dos justos permanecerá.");
    b->dados[PROVERBIOS].capitulos[12].versos[8] = _("Segundo o seu entendimento é louvado o homem; mas o perverso decoração é desprezado.");
    b->dados[PROVERBIOS].capitulos[12].versos[9] = _("Melhor é o que é estimado em pouco e tem servo, do que quem se honra a si mesmo e tem falta de pão.");
    b->dados[PROVERBIOS].capitulos[12].versos[10] = _("O justo olha pela vida dos seus animais; porém as entranhas dos ímpios são cruéis.");
    b->dados[PROVERBIOS].capitulos[12].versos[11] = _("O que lavra a sua terra se fartará de pão; mas o que segue os ociosos é falto de entendimento.");
    b->dados[PROVERBIOS].capitulos[12].versos[12] = _("Deseja o ímpio o despojo dos maus; porém a raiz dos justos produz o seu próprio fruto.");
    b->dados[PROVERBIOS].capitulos[12].versos[13] = _("Pela transgressão dos lábios se enlaça o mau; mas o justo escapa da angústia.");
    b->dados[PROVERBIOS].capitulos[12].versos[14] = _("Do fruto das suas palavras o homem se farta de bem; e das obras das suas mãos se lhe retribui.");
    b->dados[PROVERBIOS].capitulos[12].versos[15] = _("O caminho do insensato é reto aos seus olhos; mas o que dá ouvidos ao conselho é sábio.");
    b->dados[PROVERBIOS].capitulos[12].versos[16] = _("A ira do insensato logo se revela; mas o prudente encobre a afronta.");
    b->dados[PROVERBIOS].capitulos[12].versos[17] = _("Quem fala a verdade manifesta a justiça; porém a testemunha falsa produz a fraude.");
    b->dados[PROVERBIOS].capitulos[12].versos[18] = _("Há palrador cujas palavras ferem como espada; porém a língua dos sábios traz saúde.");
    b->dados[PROVERBIOS].capitulos[12].versos[19] = _("O lábio veraz permanece para sempre; mas a língua mentirosa dura só um momento.");
    b->dados[PROVERBIOS].capitulos[12].versos[20] = _("Engano há no coração dos que maquinam o mal; mas há gozo para os que aconselham a paz.");
    b->dados[PROVERBIOS].capitulos[12].versos[21] = _("Nenhuma desgraça sobrevém ao justo; mas os ímpios ficam cheios de males.");
    b->dados[PROVERBIOS].capitulos[12].versos[22] = _("Os lábios mentirosos são abomináveis ao Senhor; mas os que praticam a verdade são o seu deleite.");
    b->dados[PROVERBIOS].capitulos[12].versos[23] = _("O homem prudente encobre o conhecimento; mas o coração dos tolos proclama a estultícia.");
    b->dados[PROVERBIOS].capitulos[12].versos[24] = _("A mão dos diligentes dominará; mas o indolente será tributário servil.");
    b->dados[PROVERBIOS].capitulos[12].versos[25] = _("A ansiedade no coração do homem o abate; mas uma boa palavra o alegra.");
    b->dados[PROVERBIOS].capitulos[12].versos[26] = _("O justo é um guia para o seu próximo; mas o caminho dos ímpios os faz errar.");
    b->dados[PROVERBIOS].capitulos[12].versos[27] = _("O preguiçoso não apanha a sua caça; mas o bem precioso do homem é para o diligente.");
    b->dados[PROVERBIOS].capitulos[12].versos[28] = _("Na vereda da justiça está a vida; e no seu caminho não há morte.");

    b->dados[PROVERBIOS].capitulos[13].versos[1] = _("O filho sábio ouve a instrução do pai; mas o escarnecedor não escuta a repreensão.");
    b->dados[PROVERBIOS].capitulos[13].versos[2] = _("Do fruto da boca o homem come o bem; mas o apetite dos prevaricadores alimenta-se da violência.");
    b->dados[PROVERBIOS].capitulos[13].versos[3] = _("O que guarda a sua boca preserva a sua vida; mas o que muito abre os seus lábios traz sobre si a ruína.");
    b->dados[PROVERBIOS].capitulos[13].versos[4] = _("O preguiçoso deseja, e coisa nenhuma alcança; mas o desejo do diligente será satisfeito.");
    b->dados[PROVERBIOS].capitulos[13].versos[5] = _("O justo odeia a palavra mentirosa, mas o ímpio se faz odioso e se cobre de vergonha.");
    b->dados[PROVERBIOS].capitulos[13].versos[6] = _("A justiça guarda ao que é reto no seu caminho; mas a perversidade transtorna o pecador.");
    b->dados[PROVERBIOS].capitulos[13].versos[7] = _("Há quem se faça rico, não tendo coisa alguma; e quem se faça pobre, tendo grande riqueza.");
    b->dados[PROVERBIOS].capitulos[13].versos[8] = _("O resgate da vida do homem são as suas riquezas; mas o pobre não tem meio de se resgatar.");
    b->dados[PROVERBIOS].capitulos[13].versos[9] = _("A luz dos justos alegra; porem a lâmpada dos ímpios se apagará.");
    b->dados[PROVERBIOS].capitulos[13].versos[10] = _("Da soberba só provém a contenda; mas com os que se aconselham se acha a sabedoria.");
    b->dados[PROVERBIOS].capitulos[13].versos[11] = _("A riqueza adquirida às pressas diminuíra; mas quem a ajunta pouco a pouco terá aumento.");
    b->dados[PROVERBIOS].capitulos[13].versos[12] = _("A esperança adiada entristece o coração; mas o desejo cumprido é árvore devida.");
    b->dados[PROVERBIOS].capitulos[13].versos[13] = _("O que despreza a palavra traz sobre si a destruição; mas o que teme o mandamento será galardoado.");
    b->dados[PROVERBIOS].capitulos[13].versos[14] = _("O ensino do sábio é uma fonte devida para desviar dos laços da morte.");
    b->dados[PROVERBIOS].capitulos[13].versos[15] = _("O bom senso alcança favor; mas o caminho dos prevaricadores é áspero:");
    b->dados[PROVERBIOS].capitulos[13].versos[16] = _("Em tudo o homem prudente procede com conhecimento; mas o tolo espraia a sua insensatez.");
    b->dados[PROVERBIOS].capitulos[13].versos[17] = _("O mensageiro perverso faz cair no mal; mas o embaixador fiel traz saúde.");
    b->dados[PROVERBIOS].capitulos[13].versos[18] = _("Pobreza e afronta virão ao que rejeita a correção; mas o que guarda a repreensão será honrado.");
    b->dados[PROVERBIOS].capitulos[13].versos[19] = _("O desejo que se cumpre deleita a alma; mas apartar-se do ma e abominação para os tolos.");
    b->dados[PROVERBIOS].capitulos[13].versos[20] = _("Quem anda com os sábios será sábio; mas o companheiro dos tolos sofre aflição.");
    b->dados[PROVERBIOS].capitulos[13].versos[21] = _("O mal persegue os pecadores; mas os justos são galardoados com o bem.");
    b->dados[PROVERBIOS].capitulos[13].versos[22] = _("O homem de bem deixa uma herança aos filhos de seus filhos; a riqueza do pecador, porém, é reservada para o justo.");
    b->dados[PROVERBIOS].capitulos[13].versos[23] = _("Abundância de mantimento há, na lavoura do pobre; mas se perde por falta de juízo.");
    b->dados[PROVERBIOS].capitulos[13].versos[24] = _("Aquele que poupa a vara aborrece a seu filho; mas quem o ama, a seu tempo o castiga.");
    b->dados[PROVERBIOS].capitulos[13].versos[25] = _("O justo come e fica satisfeito; mas o apetite dos ímpios nunca se satisfaz.");

    b->dados[PROVERBIOS].capitulos[14].versos[1] = _("Toda mulher sábia edifica a sua casa; a insensata, porém, derruba-a com as suas mãos.");
    b->dados[PROVERBIOS].capitulos[14].versos[2] = _("Quem anda na sua retidão teme ao Senhor; mas aquele que é perverso nos seus caminhos despreza-o.");
    b->dados[PROVERBIOS].capitulos[14].versos[3] = _("Na boca do tolo está a vara da soberba, mas os lábios do sábio preservá-lo-ão.");
    b->dados[PROVERBIOS].capitulos[14].versos[4] = _("Onde não há bois, a manjedoura está vazia; mas pela força do boi há abundância de colheitas.");
    b->dados[PROVERBIOS].capitulos[14].versos[5] = _("A testemunha verdadeira não mentirá; a testemunha falsa, porém, se desboca em mentiras.");
    b->dados[PROVERBIOS].capitulos[14].versos[6] = _("O escarnecedor busca sabedoria, e não a encontra; mas para o prudente o conhecimento é fácil.");
    b->dados[PROVERBIOS].capitulos[14].versos[7] = _("Vai-te da presença do homem insensato, pois nele não acharás palavras de ciência.");
    b->dados[PROVERBIOS].capitulos[14].versos[8] = _("A sabedoria do prudente é entender o seu caminho; porém a estultícia dos tolos é enganar.");
    b->dados[PROVERBIOS].capitulos[14].versos[9] = _("A culpa zomba dos insensatos; mas os retos têm o favor de Deus.");
    b->dados[PROVERBIOS].capitulos[14].versos[10] = _("O coração conhece a sua própria amargura; e o estranho não participa da sua alegria.");
    b->dados[PROVERBIOS].capitulos[14].versos[11] = _("A casa dos ímpios se desfará; porém a tenda dos retos florescerá.");
    b->dados[PROVERBIOS].capitulos[14].versos[12] = _("Há um caminho que ao homem parece direito, mas o fim dele conduz à morte.");
    b->dados[PROVERBIOS].capitulos[14].versos[13] = _("Até no riso terá dor o coração; e o fim da alegria é tristeza.");
    b->dados[PROVERBIOS].capitulos[14].versos[14] = _("Dos seus próprios caminhos se fartará o infiel de coração, como também o homem bom se contentará dos seus.");
    b->dados[PROVERBIOS].capitulos[14].versos[15] = _("O simples dá crédito a tudo; mas o prudente atenta para os seus passos.");
    b->dados[PROVERBIOS].capitulos[14].versos[16] = _("O sábio teme e desvia-se do mal, mas o tolo é arrogante e dá-se por seguro.");
    b->dados[PROVERBIOS].capitulos[14].versos[17] = _("Quem facilmente se ira fará doidices; mas o homem discreto é paciente;");
    b->dados[PROVERBIOS].capitulos[14].versos[18] = _("Os simples herdam a estultícia; mas os prudentes se coroam de conhecimento.");
    b->dados[PROVERBIOS].capitulos[14].versos[19] = _("Os maus inclinam-se perante os bons; e os ímpios diante das portas dos justos.");
    b->dados[PROVERBIOS].capitulos[14].versos[20] = _("O pobre é odiado até pelo seu vizinho; mas os amigos dos ricos são muitos.");
    b->dados[PROVERBIOS].capitulos[14].versos[21] = _("O que despreza ao seu vizinho peca; mas feliz é aquele que se compadece dos pobres.");
    b->dados[PROVERBIOS].capitulos[14].versos[22] = _("Porventura não erram os que maquinam o mal? mas há beneficência e fidelidade para os que planejam o bem.");
    b->dados[PROVERBIOS].capitulos[14].versos[23] = _("Em todo trabalho há proveito; meras palavras, porém, só encaminham para a penúria.");
    b->dados[PROVERBIOS].capitulos[14].versos[24] = _("A coroa dos sábios é a sua riqueza; porém a estultícia dos tolos não passa de estultícia.");
    b->dados[PROVERBIOS].capitulos[14].versos[25] = _("A testemunha verdadeira livra as almas; mas o que fala mentiras é traidor.");
    b->dados[PROVERBIOS].capitulos[14].versos[26] = _("No temor do Senhor há firme confiança; e os seus filhos terão um lugar de refúgio.");
    b->dados[PROVERBIOS].capitulos[14].versos[27] = _("O temor do Senhor é uma fonte de vida, para o homem se desviar dos laços da morte.");
    b->dados[PROVERBIOS].capitulos[14].versos[28] = _("Na multidão do povo está a glória do rei; mas na falta de povo está a ruína do príncipe.");
    b->dados[PROVERBIOS].capitulos[14].versos[29] = _("Quem é tardio em irar-se é grande em entendimento; mas o que é de ânimo precipitado exalta a loucura.");
    b->dados[PROVERBIOS].capitulos[14].versos[30] = _("O coração tranqüilo é a vida da carne; a inveja, porém, é a podridão dos ossos.");
    b->dados[PROVERBIOS].capitulos[14].versos[31] = _("O que oprime ao pobre insulta ao seu Criador; mas honra-o aquele que se compadece do necessitado.");
    b->dados[PROVERBIOS].capitulos[14].versos[32] = _("O ímpio é derrubado pela sua malícia; mas o justo até na sua morte acha refúgio.");
    b->dados[PROVERBIOS].capitulos[14].versos[33] = _("No coração do prudente repousa a sabedoria; mas no coração dos tolos não é conhecida.");
    b->dados[PROVERBIOS].capitulos[14].versos[34] = _("A justiça exalta as nações; mas o pecado é o opróbrio dos povos.");
    b->dados[PROVERBIOS].capitulos[14].versos[35] = _("O favor do rei é concedido ao servo que procede sabiamente; mas sobre o que procede indignamente cairá o seu furor.");

    b->dados[PROVERBIOS].capitulos[15].versos[1] = _("A resposta branda desvia o furor, mas a palavra dura suscita a ira.");
    b->dados[PROVERBIOS].capitulos[15].versos[2] = _("A língua dos sábios destila o conhecimento; porém a boca dos tolos derrama a estultícia.");
    b->dados[PROVERBIOS].capitulos[15].versos[3] = _("Os olhos do Senhor estão em todo lugar, vigiando os maus e os bons.");
    b->dados[PROVERBIOS].capitulos[15].versos[4] = _("Uma língua suave é árvore de vida; mas a língua perversa quebranta o espírito.");
    b->dados[PROVERBIOS].capitulos[15].versos[5] = _("O insensato despreza a correção e seu pai; mas o que atende à admoestação prudentemente se haverá.");
    b->dados[PROVERBIOS].capitulos[15].versos[6] = _("Na casa do justo há um grande tesouro; mas nos lucros do ímpio há perturbação.");
    b->dados[PROVERBIOS].capitulos[15].versos[7] = _("Os lábios dos sábios difundem conhecimento; mas não o faz o coração dos tolos.");
    b->dados[PROVERBIOS].capitulos[15].versos[8] = _("O sacrifício dos ímpios é abominável ao Senhor; mas a oração dos retos lhe é agradável.");
    b->dados[PROVERBIOS].capitulos[15].versos[9] = _("O caminho do ímpio é abominável ao Senhor; mas ele ama ao que segue a justiça.");
    b->dados[PROVERBIOS].capitulos[15].versos[10] = _("Há disciplina severa para o que abandona a vereda; e o que aborrece a repreensão morrerá.");
    b->dados[PROVERBIOS].capitulos[15].versos[11] = _("O Seol e o Abadom estão abertos perante o Senhor; quanto mais o coração dos filhos dos homens!");
    b->dados[PROVERBIOS].capitulos[15].versos[12] = _("O escarnecedor não gosta daquele que o repreende; não irá ter com os sábios.");
    b->dados[PROVERBIOS].capitulos[15].versos[13] = _("O coração alegre aformoseia o rosto; mas pela dor do coração o espírito se abate.");
    b->dados[PROVERBIOS].capitulos[15].versos[14] = _("O coração do inteligente busca o conhecimento; mas a boca dos tolos se apascenta de estultícia.");
    b->dados[PROVERBIOS].capitulos[15].versos[15] = _("Todos os dias do aflito são maus; mas o coração contente tem um banquete contínuo.");
    b->dados[PROVERBIOS].capitulos[15].versos[16] = _("Melhor é o pouco com o temor do Senhor, do que um grande tesouro, e com ele a inquietação.");
    b->dados[PROVERBIOS].capitulos[15].versos[17] = _("Melhor é um prato de hortaliça, onde há amor, do que o boi gordo, e com ele o ódio.");
    b->dados[PROVERBIOS].capitulos[15].versos[18] = _("O homem iracundo suscita contendas; mas o longânimo apazigua a luta.");
    b->dados[PROVERBIOS].capitulos[15].versos[19] = _("O caminho do preguiçoso é como a sebe de espinhos; porém a vereda dos justos é uma estrada real.");
    b->dados[PROVERBIOS].capitulos[15].versos[20] = _("O filho sábio alegra a seu pai; mas o homem insensato despreza a sua mãe.");
    b->dados[PROVERBIOS].capitulos[15].versos[21] = _("A estultícia é alegria para o insensato; mas o homem de entendimento anda retamente.");
    b->dados[PROVERBIOS].capitulos[15].versos[22] = _("Onde não há conselho, frustram-se os projetos; mas com a multidão de conselheiros se estabelecem.");
    b->dados[PROVERBIOS].capitulos[15].versos[23] = _("O homem alegra-se em dar uma resposta adequada; e a palavra a seu tempo quão boa é!");
    b->dados[PROVERBIOS].capitulos[15].versos[24] = _("Para o sábio o caminho da vida é para cima, a fim de que ele se desvie do Seol que é em baixo.");
    b->dados[PROVERBIOS].capitulos[15].versos[25] = _("O Senhor desarraiga a casa dos soberbos, mas estabelece a herança da viúva.");
    b->dados[PROVERBIOS].capitulos[15].versos[26] = _("Os desígnios dos maus são abominação para o Senhor; mas as palavras dos limpos lhe são aprazíveis.");
    b->dados[PROVERBIOS].capitulos[15].versos[27] = _("O que se dá à cobiça perturba a sua própria casa; mas o que aborrece a peita viverá.");
    b->dados[PROVERBIOS].capitulos[15].versos[28] = _("O coração do justo medita no que há de responder; mas a boca dos ímpios derrama coisas más.");
    b->dados[PROVERBIOS].capitulos[15].versos[29] = _("Longe está o Senhor dos ímpios, mas ouve a oração dos justos.");
    b->dados[PROVERBIOS].capitulos[15].versos[30] = _("A luz dos olhos alegra o coração, e boas-novas engordam os ossos.");
    b->dados[PROVERBIOS].capitulos[15].versos[31] = _("O ouvido que escuta a advertência da vida terá a sua morada entre os sábios.");
    b->dados[PROVERBIOS].capitulos[15].versos[32] = _("Quem rejeita a correção menospreza a sua alma; mas aquele que escuta a advertência adquire entendimento.");
    b->dados[PROVERBIOS].capitulos[15].versos[33] = _("O temor do Senhor é a instrução da sabedoria; e adiante da honra vai a humildade.");

    b->dados[PROVERBIOS].capitulos[16].versos[1] = _("Ao homem pertencem os planos do coração; mas a resposta da língua é do Senhor.");
    b->dados[PROVERBIOS].capitulos[16].versos[2] = _("Todos os caminhos do homem são limpos aos seus olhos; mas o Senhor pesa os espíritos.");
    b->dados[PROVERBIOS].capitulos[16].versos[3] = _("Entrega ao Senhor as tuas obras, e teus desígnios serão estabelecidos.");
    b->dados[PROVERBIOS].capitulos[16].versos[4] = _("O Senhor fez tudo para um fim; sim, até o ímpio para o dia do mal.");
    b->dados[PROVERBIOS].capitulos[16].versos[5] = _("Todo homem arrogante é abominação ao Senhor; certamente não ficará impune.");
    b->dados[PROVERBIOS].capitulos[16].versos[6] = _("Pela misericórdia e pela verdade expia-se a iniqüidade; e pelo temor do Senhor os homens se desviam do mal.");
    b->dados[PROVERBIOS].capitulos[16].versos[7] = _("Quando os caminhos do homem agradam ao Senhor, faz que até os seus inimigos tenham paz com ele.");
    b->dados[PROVERBIOS].capitulos[16].versos[8] = _("Melhor é o pouco com justiça, do que grandes rendas com injustiça.");
    b->dados[PROVERBIOS].capitulos[16].versos[9] = _("O coração do homem propõe o seu caminho; mas o Senhor lhe dirige os passos.");
    b->dados[PROVERBIOS].capitulos[16].versos[10] = _("Nos lábios do rei acham-se oráculos; em juízo a sua boca não prevarica.");
    b->dados[PROVERBIOS].capitulos[16].versos[11] = _("O peso e a balança justos são do Senhor; obra sua são todos os pesos da bolsa.");
    b->dados[PROVERBIOS].capitulos[16].versos[12] = _("Abominação é para os reis o praticarem a impiedade; porque com justiça se estabelece o trono.");
    b->dados[PROVERBIOS].capitulos[16].versos[13] = _("Lábios justos são o prazer dos reis; e eles amam aquele que fala coisas retas.");
    b->dados[PROVERBIOS].capitulos[16].versos[14] = _("O furor do rei é mensageiro da morte; mas o homem sábio o aplacará.");
    b->dados[PROVERBIOS].capitulos[16].versos[15] = _("Na luz do semblante do rei está a vida; e o seu favor é como a nuvem de chuva serôdia.");
    b->dados[PROVERBIOS].capitulos[16].versos[16] = _("Quanto melhor é adquirir a sabedoria do que o ouro! e quanto mais excelente é escolher o entendimento do que a prata!");
    b->dados[PROVERBIOS].capitulos[16].versos[17] = _("A estrada dos retos desvia-se do mal; o que guarda o seu caminho preserva a sua vida.");
    b->dados[PROVERBIOS].capitulos[16].versos[18] = _("A soberba precede a destruição, e a altivez do espírito precede a queda.");
    b->dados[PROVERBIOS].capitulos[16].versos[19] = _("Melhor é ser humilde de espírito com os mansos, do que repartir o despojo com os soberbos.");
    b->dados[PROVERBIOS].capitulos[16].versos[20] = _("O que atenta prudentemente para a palavra prosperará; e feliz é aquele que confia no Senhor.");
    b->dados[PROVERBIOS].capitulos[16].versos[21] = _("O sábio de coração será chamado prudente; e a doçura dos lábios aumenta o saber.");
    b->dados[PROVERBIOS].capitulos[16].versos[22] = _("O entendimento, para aquele que o possui, é uma fonte de vida, porém a estultícia é o castigo dos insensatos.");
    b->dados[PROVERBIOS].capitulos[16].versos[23] = _("O coração do sábio instrui a sua boca, e aumenta o saber nos seus lábios.");
    b->dados[PROVERBIOS].capitulos[16].versos[24] = _("Palavras suaves são como favos de mel, doçura para a alma e saúde para o corpo.");
    b->dados[PROVERBIOS].capitulos[16].versos[25] = _("Há um caminho que ao homem parece direito, mas o fim dele conduz à morte.");
    b->dados[PROVERBIOS].capitulos[16].versos[26] = _("O apetite do trabalhador trabalha por ele, porque a sua fome o incita a isso.");
    b->dados[PROVERBIOS].capitulos[16].versos[27] = _("O homem vil suscita o mal; e nos seus lábios há como que um fogo ardente.");
    b->dados[PROVERBIOS].capitulos[16].versos[28] = _("O homem perverso espalha contendas; e o difamador separa amigos íntimos.");
    b->dados[PROVERBIOS].capitulos[16].versos[29] = _("O homem violento alicia o seu vizinho, e guia-o por um caminho que não é bom.");
    b->dados[PROVERBIOS].capitulos[16].versos[30] = _("Quando fecha os olhos fá-lo para maquinar perversidades; quando morde os lábios, efetua o mal.");
    b->dados[PROVERBIOS].capitulos[16].versos[31] = _("Coroa de honra são as cãs, a qual se obtém no caminho da justiça.");
    b->dados[PROVERBIOS].capitulos[16].versos[32] = _("Melhor é o longânimo do que o valente; e o que domina o seu espírito do que o que toma uma cidade.");
    b->dados[PROVERBIOS].capitulos[16].versos[33] = _("A sorte se lança no regaço; mas do Senhor procede toda a disposição dela.");

    b->dados[PROVERBIOS].capitulos[17].versos[1] = _("Melhor é um bocado seco, e com ele a tranqüilidade, do que a casa cheia de festins, com rixas.");
    b->dados[PROVERBIOS].capitulos[17].versos[2] = _("O servo prudente dominará sobre o filho que procede indignamente; e entre os irmãos receberá da herança.");
    b->dados[PROVERBIOS].capitulos[17].versos[3] = _("O crisol é para a prata, e o forno para o ouro; mas o Senhor é que prova os corações.");
    b->dados[PROVERBIOS].capitulos[17].versos[4] = _("O malfazejo atenta para o lábio iníquo; o mentiroso inclina os ouvidos para a língua maligna.");
    b->dados[PROVERBIOS].capitulos[17].versos[5] = _("O que escarnece do pobre insulta ao seu Criador; o que se alegra da calamidade não ficará impune.");
    b->dados[PROVERBIOS].capitulos[17].versos[6] = _("Coroa dos velhos são os filhos dos filhos; e a glória dos filhos são seus pais.");
    b->dados[PROVERBIOS].capitulos[17].versos[7] = _("Não convém ao tolo a fala excelente; quanto menos ao príncipe o lábio mentiroso!");
    b->dados[PROVERBIOS].capitulos[17].versos[8] = _("Pedra preciosa é a peita aos olhos de quem a oferece; para onde quer que ele se volte, serve-lhe de proveito.");
    b->dados[PROVERBIOS].capitulos[17].versos[9] = _("O que perdoa a transgressão busca a amizade; mas o que renova a questão, afastam amigos íntimos.");
    b->dados[PROVERBIOS].capitulos[17].versos[10] = _("Mais profundamente entra a repreensão no prudente, do que cem açoites no insensato.");
    b->dados[PROVERBIOS].capitulos[17].versos[11] = _("O rebelde não busca senão o mal; portanto um mensageiro cruel será enviado contra ele.");
    b->dados[PROVERBIOS].capitulos[17].versos[12] = _("Encontre-se o homem com a ursa roubada dos filhotes, mas não com o insensato na sua estultícia.");
    b->dados[PROVERBIOS].capitulos[17].versos[13] = _("Quanto àquele que torna mal por bem, não se apartará o mal da sua casa.");
    b->dados[PROVERBIOS].capitulos[17].versos[14] = _("O princípio da contenda é como o soltar de águas represadas; deixa por isso a porfia, antes que haja rixas.");
    b->dados[PROVERBIOS].capitulos[17].versos[15] = _("O que justifica o ímpio, e o que condena o justo, são abomináveis ao Senhor, tanto um como o outro.");
    b->dados[PROVERBIOS].capitulos[17].versos[16] = _("De que serve o preço na mão do tolo para comprar a sabedoria, visto que ele não tem entendimento?");
    b->dados[PROVERBIOS].capitulos[17].versos[17] = _("O amigo ama em todo o tempo; e para a angústia nasce o irmão.");
    b->dados[PROVERBIOS].capitulos[17].versos[18] = _("O homem falto de entendimento compromete-se, tornando-se fiador na presença do seu vizinho.");
    b->dados[PROVERBIOS].capitulos[17].versos[19] = _("O que ama a contenda ama a transgressão; o que faz alta a sua porta busca a ruína.");
    b->dados[PROVERBIOS].capitulos[17].versos[20] = _("O perverso de coração nunca achará o bem; e o que tem a língua dobre virá a cair no mal.");
    b->dados[PROVERBIOS].capitulos[17].versos[21] = _("O que gera um tolo, para sua tristeza o faz; e o pai do insensato não se alegrará.");
    b->dados[PROVERBIOS].capitulos[17].versos[22] = _("O coração alegre serve de bom remédio; mas o espírito abatido seca os ossos.");
    b->dados[PROVERBIOS].capitulos[17].versos[23] = _("O ímpio recebe do regaço a peita, para perverter as veredas da justiça.");
    b->dados[PROVERBIOS].capitulos[17].versos[24] = _("O alvo do inteligente é a sabedoria; mas os olhos do insensato estão nas extremidades da terra.");
    b->dados[PROVERBIOS].capitulos[17].versos[25] = _("O filho insensato é tristeza para seu, pai, e amargura para quem o deu à luz.");
    b->dados[PROVERBIOS].capitulos[17].versos[26] = _("Não é bom punir ao justo, nem ferir aos nobres por causa da sua retidão.");
    b->dados[PROVERBIOS].capitulos[17].versos[27] = _("Refreia as suas palavras aquele que possui o conhecimento; e o homem de entendimento é de espírito sereno.");
    b->dados[PROVERBIOS].capitulos[17].versos[28] = _("Até o tolo, estando calado, é tido por sábio; e o que cerra os seus lábios, por entendido.");

    b->dados[PROVERBIOS].capitulos[18].versos[1] = _("Aquele que vive isolado busca seu próprio desejo; insurge-se contra a verdadeira sabedoria.");
    b->dados[PROVERBIOS].capitulos[18].versos[2] = _("O tolo não toma prazer no entendimento, mas tão somente em revelar a sua opinião.");
    b->dados[PROVERBIOS].capitulos[18].versos[3] = _("Quando vem o ímpio, vem também o desprezo; e com a desonra vem o opróbrio.");
    b->dados[PROVERBIOS].capitulos[18].versos[4] = _("Águas profundas são as palavras da boca do homem; e a fonte da sabedoria é um ribeiro que corre.");
    b->dados[PROVERBIOS].capitulos[18].versos[5] = _("Não é bom ter respeito à pessoa do ímpio, nem privar o justo do seu direito.");
    b->dados[PROVERBIOS].capitulos[18].versos[6] = _("Os lábios do tolo entram em contendas, e a sua boca clama por açoites.");
    b->dados[PROVERBIOS].capitulos[18].versos[7] = _("A boca do tolo é a sua própria destruição, e os seus lábios um laço para a sua alma.");
    b->dados[PROVERBIOS].capitulos[18].versos[8] = _("As palavras do difamador são como bocados doces, que penetram até o íntimo das entranhas.");
    b->dados[PROVERBIOS].capitulos[18].versos[9] = _("Aquele que é remisso na sua obra é irmão do que é destruidor.");
    b->dados[PROVERBIOS].capitulos[18].versos[10] = _("Torre forte é o nome do Senhor; para ela corre o justo, e está seguro.");
    b->dados[PROVERBIOS].capitulos[18].versos[11] = _("Os bens do rico são a sua cidade forte, e como um muro alto na sua imaginação.");
    b->dados[PROVERBIOS].capitulos[18].versos[12] = _("Antes da ruína eleva-se o coração do homem; e adiante da honra vai a humildade.");
    b->dados[PROVERBIOS].capitulos[18].versos[13] = _("Responder antes de ouvir, é estultícia e vergonha.");
    b->dados[PROVERBIOS].capitulos[18].versos[14] = _("O espírito do homem o sustentará na sua enfermidade; mas ao espírito abatido quem o levantará?");
    b->dados[PROVERBIOS].capitulos[18].versos[15] = _("O coração do entendido adquire conhecimento; e o ouvido dos sábios busca conhecimento;");
    b->dados[PROVERBIOS].capitulos[18].versos[16] = _("O presente do homem alarga-lhe o caminho, e leva-o à presença dos grandes.");
    b->dados[PROVERBIOS].capitulos[18].versos[17] = _("O que primeiro começa o seu pleito parece justo; até que vem o outro e o examina.");
    b->dados[PROVERBIOS].capitulos[18].versos[18] = _("A sorte faz cessar os pleitos, e decide entre os poderosos.");
    b->dados[PROVERBIOS].capitulos[18].versos[19] = _("um irmão ajudado pelo irmão é como uma cidade fortificada; é forte como os ferrolhos dum castelo.");
    b->dados[PROVERBIOS].capitulos[18].versos[20] = _("O homem se fartará do fruto da sua boca; dos renovos dos seus lábios se fartará.");
    b->dados[PROVERBIOS].capitulos[18].versos[21] = _("A morte e a vida estão no poder da língua; e aquele que a ama comerá do seu fruto.");
    b->dados[PROVERBIOS].capitulos[18].versos[22] = _("Quem encontra uma esposa acha uma coisa boa; e alcança o favor do Senhor.");
    b->dados[PROVERBIOS].capitulos[18].versos[23] = _("O pobre fala com rogos; mas o rico responde com durezas.");
    b->dados[PROVERBIOS].capitulos[18].versos[24] = _("O homem que tem muitos amigos, tem-nos para a sua ruína; mas há um amigo que é mais chegado do que um irmão.");

    b->dados[PROVERBIOS].capitulos[19].versos[1] = _("Melhor é o pobre que anda na sua integridade, do que aquele que é perverso de lábios e tolo.");
    b->dados[PROVERBIOS].capitulos[19].versos[2] = _("Não é bom agir sem refletir; e o que se apressa com seus pés erra o caminho.");
    b->dados[PROVERBIOS].capitulos[19].versos[3] = _("A estultícia do homem perverte o seu caminho, e o seu coração se irrita contra o Senhor.");
    b->dados[PROVERBIOS].capitulos[19].versos[4] = _("As riquezas granjeiam muitos amigos; mas do pobre o seu próprio amigo se separa.");
    b->dados[PROVERBIOS].capitulos[19].versos[5] = _("A testemunha falsa não ficará impune; e o que profere mentiras não escapará.");
    b->dados[PROVERBIOS].capitulos[19].versos[6] = _("Muitos procurarão o favor do liberal; e cada um é amigo daquele que dá presentes.");
    b->dados[PROVERBIOS].capitulos[19].versos[7] = _("Todos os irmãos do pobre o aborrecem; quanto mais se afastam dele os seus amigos! persegue-os com súplicas, mas eles já se foram.");
    b->dados[PROVERBIOS].capitulos[19].versos[8] = _("O que adquire a sabedoria é amigo de si mesmo; o que guarda o entendimento prosperará.");
    b->dados[PROVERBIOS].capitulos[19].versos[9] = _("A testemunha falsa não ficará impune, e o que profere mentiras perecerá.");
    b->dados[PROVERBIOS].capitulos[19].versos[10] = _("Ao tolo não convém o luxo; quanto menos ao servo dominar os príncipes!");
    b->dados[PROVERBIOS].capitulos[19].versos[11] = _("A discrição do homem fá-lo tardio em irar-se; e sua glória está em esquecer ofensas.");
    b->dados[PROVERBIOS].capitulos[19].versos[12] = _("A ira do rei é como o bramido o leão; mas o seu favor é como o orvalho sobre a erva.");
    b->dados[PROVERBIOS].capitulos[19].versos[13] = _("O filho insensato é a calamidade do pai; e as rixas da mulher são uma goteira contínua.");
    b->dados[PROVERBIOS].capitulos[19].versos[14] = _("Casa e riquezas são herdadas dos pais; mas a mulher prudente vem do Senhor.");
    b->dados[PROVERBIOS].capitulos[19].versos[15] = _("A preguiça faz cair em profundo sono; e o ocioso padecerá fome.");
    b->dados[PROVERBIOS].capitulos[19].versos[16] = _("Quem guarda o mandamento guarda a sua alma; mas aquele que não faz caso dos seus caminhos morrerá.");
    b->dados[PROVERBIOS].capitulos[19].versos[17] = _("O que se compadece do pobre empresta ao Senhor, que lhe retribuirá o seu benefício.");
    b->dados[PROVERBIOS].capitulos[19].versos[18] = _("Corrige a teu filho enquanto há esperança; mas não te incites a destruí-lo.");
    b->dados[PROVERBIOS].capitulos[19].versos[19] = _("Homem de grande ira tem de sofrer o castigo; porque se o livrares, terás de o fazer de novo.");
    b->dados[PROVERBIOS].capitulos[19].versos[20] = _("Ouve o conselho, e recebe a correção, para que sejas sábio nos teus últimos dias.");
    b->dados[PROVERBIOS].capitulos[19].versos[21] = _("Muitos são os planos no coração do homem; mas o desígnio do Senhor, esse prevalecerá.");
    b->dados[PROVERBIOS].capitulos[19].versos[22] = _("O que faz um homem desejável é a sua benignidade; e o pobre é melhor do que o mentiroso.");
    b->dados[PROVERBIOS].capitulos[19].versos[23] = _("O temor do Senhor encaminha para a vida; aquele que o tem ficará satisfeito, e mal nenhum o visitará.");
    b->dados[PROVERBIOS].capitulos[19].versos[24] = _("O preguiçoso esconde a sua mão no prato, e nem ao menos quer levá-la de novo à boca.");
    b->dados[PROVERBIOS].capitulos[19].versos[25] = _("Fere ao escarnecedor, e o simples aprenderá a prudência; repreende ao que tem entendimento, e ele crescerá na ciência.");
    b->dados[PROVERBIOS].capitulos[19].versos[26] = _("O que aflige a seu pai, e faz fugir a sua mãe, é filho que envergonha e desonra.");
    b->dados[PROVERBIOS].capitulos[19].versos[27] = _("Cessa, filho meu, de ouvir a instrução, e logo te desviarás das palavras do conhecimento.");
    b->dados[PROVERBIOS].capitulos[19].versos[28] = _("A testemunha vil escarnece da justiça; e a boca dos ímpios engole a iniqüidade.");
    b->dados[PROVERBIOS].capitulos[19].versos[29] = _("A condenação está preparada para os escarnecedores, e os açoites para as costas dos tolos.");

    b->dados[PROVERBIOS].capitulos[20].versos[1] = _("O vinho é escarnecedor, e a bebida forte alvoroçadora; e todo aquele que neles errar não e sábio.");
    b->dados[PROVERBIOS].capitulos[20].versos[2] = _("Como o bramido do leão é o terror do rei; quem o provoca a ira peca contra a sua própria vida.");
    b->dados[PROVERBIOS].capitulos[20].versos[3] = _("Honroso é para o homem o desviar-se de questões; mas todo insensato se entremete nelas.");
    b->dados[PROVERBIOS].capitulos[20].versos[4] = _("O preguiçoso não lavra no outono; pelo que mendigará na sega, e nada receberá.");
    b->dados[PROVERBIOS].capitulos[20].versos[5] = _("Como águas profundas é o propósito no coração do homem; mas o homem inteligente o descobrirá.");
    b->dados[PROVERBIOS].capitulos[20].versos[6] = _("Muitos há que proclamam a sua própria bondade; mas o homem fiel, quem o achará?");
    b->dados[PROVERBIOS].capitulos[20].versos[7] = _("O justo anda na sua integridade; bem-aventurados serão os seus filhos depois dele.");
    b->dados[PROVERBIOS].capitulos[20].versos[8] = _("Assentando-se o rei no trono do juízo, com os seus olhos joeira a todo malfeitor.");
    b->dados[PROVERBIOS].capitulos[20].versos[9] = _("Quem pode dizer: Purifiquei o meu coração, limpo estou de meu pecado?");
    b->dados[PROVERBIOS].capitulos[20].versos[10] = _("O peso fraudulento e a medida falsa são abominação ao Senhor, tanto uma como outra coisa.");
    b->dados[PROVERBIOS].capitulos[20].versos[11] = _("Até a criança se dá a conhecer pelas suas ações, se a sua conduta é pura e reta.");
    b->dados[PROVERBIOS].capitulos[20].versos[12] = _("O ouvido que ouve, e o olho que vê, o Senhor os fez a ambos.");
    b->dados[PROVERBIOS].capitulos[20].versos[13] = _("Não ames o sono, para que não empobreças; abre os teus olhos, e te fartarás de pão.");
    b->dados[PROVERBIOS].capitulos[20].versos[14] = _("Nada vale, nada vale, diz o comprador; mas, depois de retirar-se, então se gaba.");
    b->dados[PROVERBIOS].capitulos[20].versos[15] = _("Há ouro e abundância de pedras preciosas; mas os lábios do conhecimento são jóia de grande valor.");
    b->dados[PROVERBIOS].capitulos[20].versos[16] = _("Tira a roupa àquele que fica por fiador do estranho; e toma penhor daquele que se obriga por estrangeiros.");
    b->dados[PROVERBIOS].capitulos[20].versos[17] = _("Suave é ao homem o pão da mentira; mas depois a sua boca se enche de pedrinhas.");
    b->dados[PROVERBIOS].capitulos[20].versos[18] = _("Os projetos se confirmam pelos conselhos; assim, pois, com prudência faze a guerra.");
    b->dados[PROVERBIOS].capitulos[20].versos[19] = _("O que anda mexericando revela segredos; pelo que não te metas com quem muito abre os seus lábios.");
    b->dados[PROVERBIOS].capitulos[20].versos[20] = _("O que amaldiçoa a seu pai ou a sua mãe, apagar-se-lhe-á a sua lâmpada nas, mais densas trevas.");
    b->dados[PROVERBIOS].capitulos[20].versos[21] = _("A herança que no princípio é adquirida às pressas, não será abençoada no seu fim.");
    b->dados[PROVERBIOS].capitulos[20].versos[22] = _("Não digas: vingar-me-ei do mal; espera pelo Senhor e ele te livrará.");
    b->dados[PROVERBIOS].capitulos[20].versos[23] = _("Pesos fraudulentos são abomináveis ao Senhor; e balanças enganosas não são boas.");
    b->dados[PROVERBIOS].capitulos[20].versos[24] = _("Os passos do homem são dirigidos pelo Senhor; como, pois, poderá o homem entender o seu caminho?");
    b->dados[PROVERBIOS].capitulos[20].versos[25] = _("Laço é para o homem dizer precipitadamente: É santo; e, feitos os votos, então refletir.");
    b->dados[PROVERBIOS].capitulos[20].versos[26] = _("O rei sábio joeira os ímpios e faz girar sobre eles a roda.");
    b->dados[PROVERBIOS].capitulos[20].versos[27] = _("O espírito do homem é a lâmpada do Senhor, a qual esquadrinha todo o mais íntimo do coração.");
    b->dados[PROVERBIOS].capitulos[20].versos[28] = _("A benignidade e a verdade guardam o rei; e com a benignidade sustém ele o seu trono.");
    b->dados[PROVERBIOS].capitulos[20].versos[29] = _("A glória dos jovens é a sua força; e a beleza dos velhos são as cãs.");
    b->dados[PROVERBIOS].capitulos[20].versos[30] = _("Os açoites que ferem purificam do mal; e as feridas penetram até o mais íntimo do corpo.");

    b->dados[PROVERBIOS].capitulos[21].versos[1] = _("Como corrente de águas é o coração do rei na mão do Senhor; ele o inclina para onde quer.");
    b->dados[PROVERBIOS].capitulos[21].versos[2] = _("Todo caminho do homem é reto aos seus olhos; mas o Senhor pesa os corações.");
    b->dados[PROVERBIOS].capitulos[21].versos[3] = _("Fazer justiça e julgar com retidão é mais aceitável ao Senhor do que oferecer-lhe sacrifício.");
    b->dados[PROVERBIOS].capitulos[21].versos[4] = _("Olhar altivo e coração orgulhoso, tal lâmpada dos ímpios é pecado.");
    b->dados[PROVERBIOS].capitulos[21].versos[5] = _("Os planos do diligente conduzem à abundância; mas todo precipitado apressa-se para a penúria.");
    b->dados[PROVERBIOS].capitulos[21].versos[6] = _("Ajuntar tesouros com língua falsa é uma vaidade fugitiva; aqueles que os buscam, buscam a morte.");
    b->dados[PROVERBIOS].capitulos[21].versos[7] = _("A violência dos ímpios arrebatá-los-á, porquanto recusam praticar a justiça.");
    b->dados[PROVERBIOS].capitulos[21].versos[8] = _("O caminho do homem perverso é tortuoso; mas o proceder do puro é reto.");
    b->dados[PROVERBIOS].capitulos[21].versos[9] = _("Melhor é morar num canto do eirado, do que com a mulher rixosa numa casa ampla.");
    b->dados[PROVERBIOS].capitulos[21].versos[10] = _("A alma do ímpio deseja o mal; o seu próximo não agrada aos seus olhos.");
    b->dados[PROVERBIOS].capitulos[21].versos[11] = _("Quando o escarnecedor é castigado, o simples torna-se sábio; e, quando o sábio é instruído, recebe o conhecimento.");
    b->dados[PROVERBIOS].capitulos[21].versos[12] = _("O justo observa a casa do ímpio; precipitam-se os ímpios na ruína.");
    b->dados[PROVERBIOS].capitulos[21].versos[13] = _("Quem tapa o seu ouvido ao clamor do pobre, também clamará e não será ouvido.");
    b->dados[PROVERBIOS].capitulos[21].versos[14] = _("O presente que se dá em segredo aplaca a ira; e a dádiva às escondidas, a forte indignação.");
    b->dados[PROVERBIOS].capitulos[21].versos[15] = _("A execução da justiça é motivo de alegria para o justo; mas é espanto para os que praticam a iniqüidade.");
    b->dados[PROVERBIOS].capitulos[21].versos[16] = _("O homem que anda desviado do caminho do entendimento repousará na congregação dos mortos.");
    b->dados[PROVERBIOS].capitulos[21].versos[17] = _("Quem ama os prazeres empobrecerá; quem ama o vinho e o azeite nunca enriquecera.");
    b->dados[PROVERBIOS].capitulos[21].versos[18] = _("Resgate para o justo é o ímpio; e em lugar do reto ficará o prevaricador.");
    b->dados[PROVERBIOS].capitulos[21].versos[19] = _("Melhor é morar numa terra deserta do que com a mulher rixosa e iracunda.");
    b->dados[PROVERBIOS].capitulos[21].versos[20] = _("Há tesouro precioso e azeite na casa do sábio; mas o homem insensato os devora.");
    b->dados[PROVERBIOS].capitulos[21].versos[21] = _("Aquele que segue a justiça e a bondade achará a vida, a justiça e a honra.");
    b->dados[PROVERBIOS].capitulos[21].versos[22] = _("O sábio escala a cidade dos valentes, e derriba a fortaleza em que ela confia.");
    b->dados[PROVERBIOS].capitulos[21].versos[23] = _("O que guarda a sua boca e a sua língua, guarda das angústias a sua alma.");
    b->dados[PROVERBIOS].capitulos[21].versos[24] = _("Quanto ao soberbo e presumido, zombador é seu nome; ele procede com insolente orgulho.");
    b->dados[PROVERBIOS].capitulos[21].versos[25] = _("O desejo do preguiçoso o mata; porque as suas mãos recusam-se a trabalhar.");
    b->dados[PROVERBIOS].capitulos[21].versos[26] = _("Todo o dia o ímpio cobiça; mas o justo dá, e não retém.");
    b->dados[PROVERBIOS].capitulos[21].versos[27] = _("O sacrifício dos ímpios é abominação; quanto mais oferecendo-o com intenção maligna!");
    b->dados[PROVERBIOS].capitulos[21].versos[28] = _("A testemunha mentirosa perecerá; mas o homem que ouve falará sem ser contestado.");
    b->dados[PROVERBIOS].capitulos[21].versos[29] = _("O homem ímpio endurece o seu rosto; mas o reto considera os seus caminhos.");
    b->dados[PROVERBIOS].capitulos[21].versos[30] = _("Não há sabedoria, nem entendimento, nem conselho contra o Senhor.");
    b->dados[PROVERBIOS].capitulos[21].versos[31] = _("O cavalo prepara-se para o dia da batalha; mas do Senhor vem a vitória.");

    b->dados[PROVERBIOS].capitulos[22].versos[1] = _("Mais digno de ser escolhido é o bom nome do que as muitas riquezas; e o favor é melhor do que a prata e o ouro.");
    b->dados[PROVERBIOS].capitulos[22].versos[2] = _("O rico e o pobre se encontram; quem os faz a ambos é o Senhor.");
    b->dados[PROVERBIOS].capitulos[22].versos[3] = _("O prudente vê o perigo e esconde-se; mas os simples passam adiante e sofrem a pena.");
    b->dados[PROVERBIOS].capitulos[22].versos[4] = _("O galardão da humildade e do temor do Senhor é riquezas, e honra e vida.");
    b->dados[PROVERBIOS].capitulos[22].versos[5] = _("Espinhos e laços há no caminho do perverso; o que guarda a sua alma retira-se para longe deles.");
    b->dados[PROVERBIOS].capitulos[22].versos[6] = _("Instrui o menino no caminho em que deve andar, e até quando envelhecer não se desviará dele.");
    b->dados[PROVERBIOS].capitulos[22].versos[7] = _("O rico domina sobre os pobres; e o que toma emprestado é servo do que empresta.");
    b->dados[PROVERBIOS].capitulos[22].versos[8] = _("O que semear a perversidade segará males; e a vara da sua indignação falhará.");
    b->dados[PROVERBIOS].capitulos[22].versos[9] = _("Quem vê com olhos bondosos será abençoado; porque dá do seu pão ao pobre.");
    b->dados[PROVERBIOS].capitulos[22].versos[10] = _("Lança fora ao escarnecedor, e a contenda se irá; cessarão a rixa e a injúria.");
    b->dados[PROVERBIOS].capitulos[22].versos[11] = _("O que ama a pureza do coração, e que tem graça nos seus lábios, terá por seu amigo o rei.");
    b->dados[PROVERBIOS].capitulos[22].versos[12] = _("Os olhos do Senhor preservam o que tem conhecimento; mas ele transtorna as palavras do prevaricador.");
    b->dados[PROVERBIOS].capitulos[22].versos[13] = _("Diz o preguiçoso: um leão está lá fora; serei morto no meio das ruas.");
    b->dados[PROVERBIOS].capitulos[22].versos[14] = _("Cova profunda é a boca da adúltera; aquele contra quem o Senhor está irado cairá nela.");
    b->dados[PROVERBIOS].capitulos[22].versos[15] = _("A estultícia está ligada ao coração do menino; mas a vara da correção a afugentará dele.");
    b->dados[PROVERBIOS].capitulos[22].versos[16] = _("O que para aumentar o seu lucro oprime o pobre, e dá ao rico, certamente chegará à: penúria.");
    b->dados[PROVERBIOS].capitulos[22].versos[17] = _("Inclina o teu ouvido e ouve as palavras dos sábios, e aplica o teu coração ao meu conhecimento.");
    b->dados[PROVERBIOS].capitulos[22].versos[18] = _("Porque será coisa suave, se os guardares no teu peito, se estiverem todos eles prontos nos teus lábios.");
    b->dados[PROVERBIOS].capitulos[22].versos[19] = _("Para que a tua confiança esteja no senhor, a ti tos fiz saber hoje, sim, a ti mesmo.");
    b->dados[PROVERBIOS].capitulos[22].versos[20] = _("Porventura não te escrevi excelentes coisas acerca dos conselhos e do conhecimento,");
    b->dados[PROVERBIOS].capitulos[22].versos[21] = _("para te fazer saber a certeza das palavras de verdade, para que possas responder com palavras de verdade aos que te enviarem?");
    b->dados[PROVERBIOS].capitulos[22].versos[22] = _("Não roubes ao pobre, porque é pobre; nem oprimas ao aflito na porta;");
    b->dados[PROVERBIOS].capitulos[22].versos[23] = _("porque o Senhor defenderá a sua causa em juízo, e aos que os roubam lhes tirará a vida.");
    b->dados[PROVERBIOS].capitulos[22].versos[24] = _("Não faças amizade com o iracundo; nem andes com o homem colérico;");
    b->dados[PROVERBIOS].capitulos[22].versos[25] = _("para que não aprendas as suas veredas, e tomes um laço para a tua alma.");
    b->dados[PROVERBIOS].capitulos[22].versos[26] = _("Não estejas entre os que se comprometem, que ficam por fiadores de dívidas.");
    b->dados[PROVERBIOS].capitulos[22].versos[27] = _("Se não tens com que pagar, por que tirariam a tua cama de debaixo de ti?");
    b->dados[PROVERBIOS].capitulos[22].versos[28] = _("Não removas os limites antigos que teus pais fixaram.");
    b->dados[PROVERBIOS].capitulos[22].versos[29] = _("Vês um homem hábil na sua obrar? esse perante reis assistirá; e não assistirá perante homens obscuros.");

    b->dados[PROVERBIOS].capitulos[23].versos[1] = _("Quando te assentares a comer com um governador, atenta bem para aquele que está diante de ti;");
    b->dados[PROVERBIOS].capitulos[23].versos[2] = _("e põe uma faca à tua garganta, se fores homem de grande apetite.");
    b->dados[PROVERBIOS].capitulos[23].versos[3] = _("Não cobices os seus manjares gostosos, porque é comida enganadora.");
    b->dados[PROVERBIOS].capitulos[23].versos[4] = _("Não te fatigues para seres rico; dá de mão à tua própria sabedoria:");
    b->dados[PROVERBIOS].capitulos[23].versos[5] = _("Fitando tu os olhos nas riquezas, elas se vão; pois fazem para si asas, como a águia, voam para o céu.");
    b->dados[PROVERBIOS].capitulos[23].versos[6] = _("Não comas o pão do avarento, nem cobices os seus manjares gostosos.");
    b->dados[PROVERBIOS].capitulos[23].versos[7] = _("Porque, como ele pensa consigo mesmo, assim é; ele te diz: Come e bebe; mas o seu coração não está contigo.");
    b->dados[PROVERBIOS].capitulos[23].versos[8] = _("Vomitarás o bocado que comeste, e perderás as tuas suaves palavras.");
    b->dados[PROVERBIOS].capitulos[23].versos[9] = _("Não fales aos ouvidos do tolo; porque desprezará a sabedoria das tuas palavras.");
    b->dados[PROVERBIOS].capitulos[23].versos[10] = _("Não removas os limites antigos; nem entres nos campos dos órfãos,");
    b->dados[PROVERBIOS].capitulos[23].versos[11] = _("porque o seu redentor é forte; ele lhes pleiteará a causa contra ti.");
    b->dados[PROVERBIOS].capitulos[23].versos[12] = _("Aplica o teu coração à instrução, e os teus ouvidos às palavras do conhecimento.");
    b->dados[PROVERBIOS].capitulos[23].versos[13] = _("Não retires da criança a disciplina; porque, fustigando-a tu com a vara, nem por isso morrerá.");
    b->dados[PROVERBIOS].capitulos[23].versos[14] = _("Tu a fustigarás com a vara e livrarás a sua alma do Seol.");
    b->dados[PROVERBIOS].capitulos[23].versos[15] = _("Filho meu, se o teu coração for sábio, alegrar-se-á o meu coração, sim, ó, meu próprio;");
    b->dados[PROVERBIOS].capitulos[23].versos[16] = _("e exultará o meu coração, quando os teus lábios falarem coisas retas.");
    b->dados[PROVERBIOS].capitulos[23].versos[17] = _("Não tenhas inveja dos pecadores; antes conserva-te no temor do Senhor todo o dia.");
    b->dados[PROVERBIOS].capitulos[23].versos[18] = _("Porque deveras terás uma recompensa; não será malograda a tua esperança.");
    b->dados[PROVERBIOS].capitulos[23].versos[19] = _("Ouve tu, filho meu, e sê sábio; e dirige no caminho o teu coração.");
    b->dados[PROVERBIOS].capitulos[23].versos[20] = _("Não estejas entre os beberrões de vinho, nem entre os comilões de carne.");
    b->dados[PROVERBIOS].capitulos[23].versos[21] = _("Porque o beberrão e o comilão caem em pobreza; e a sonolência cobrirá de trapos o homem.");
    b->dados[PROVERBIOS].capitulos[23].versos[22] = _("Ouve a teu pai, que te gerou; e não desprezes a tua mãe, quando ela envelhecer.");
    b->dados[PROVERBIOS].capitulos[23].versos[23] = _("Compra a verdade, e não a vendas; sim, a sabedoria, a disciplina, e o entendimento.");
    b->dados[PROVERBIOS].capitulos[23].versos[24] = _("Grandemente se regozijará o pai do justo; e quem gerar um filho sábio, nele se alegrará.");
    b->dados[PROVERBIOS].capitulos[23].versos[25] = _("Alegrem-se teu pai e tua mãe, e regozije-se aquela que te deu à luz.");
    b->dados[PROVERBIOS].capitulos[23].versos[26] = _("Filho meu, dá-me o teu coração; e deleitem-se os teus olhos nos meus caminhos.");
    b->dados[PROVERBIOS].capitulos[23].versos[27] = _("Porque cova profunda é a prostituta; e poço estreito é a aventureira.");
    b->dados[PROVERBIOS].capitulos[23].versos[28] = _("Também ela, como o salteador, se põe a espreitar; e multiplica entre os homens os prevaricadores.");
    b->dados[PROVERBIOS].capitulos[23].versos[29] = _("Para quem são os ais? para quem os pesares? para quem as pelejas, para quem as queixas? para quem as feridas sem causa? e para quem os olhos vermelhos?");
    b->dados[PROVERBIOS].capitulos[23].versos[30] = _("Para os que se demoram perto do vinho, para os que andam buscando bebida misturada.");
    b->dados[PROVERBIOS].capitulos[23].versos[31] = _("Não olhes para o vinho quando se mostra vermelho, quando resplandece no copo e se escoa suavemente.");
    b->dados[PROVERBIOS].capitulos[23].versos[32] = _("No seu fim morderá como a cobra, e como o basilisco picará.");
    b->dados[PROVERBIOS].capitulos[23].versos[33] = _("Os teus olhos verão coisas estranhas, e tu falarás perversidades.");
    b->dados[PROVERBIOS].capitulos[23].versos[34] = _("o serás como o que se deita no meio do mar, e como o que dorme no topo do mastro.");
    b->dados[PROVERBIOS].capitulos[23].versos[35] = _("E dirás: Espancaram-me, e não me doeu; bateram-me, e não o senti; quando virei a despertar? ainda tornarei a buscá-lo outra vez.");

    b->dados[PROVERBIOS].capitulos[24].versos[1] = _("Não tenhas inveja dos homens malignos; nem desejes estar com eles;");
    b->dados[PROVERBIOS].capitulos[24].versos[2] = _("porque o seu coração medita a violência; e os seus lábios falam maliciosamente.");
    b->dados[PROVERBIOS].capitulos[24].versos[3] = _("Com a sabedoria se edifica a casa, e com o entendimento ela se estabelece;");
    b->dados[PROVERBIOS].capitulos[24].versos[4] = _("e pelo conhecimento se encherão as câmaras de todas as riquezas preciosas e deleitáveis.");
    b->dados[PROVERBIOS].capitulos[24].versos[5] = _("O sábio é mais poderoso do que o forte; e o inteligente do que o que possui a força.");
    b->dados[PROVERBIOS].capitulos[24].versos[6] = _("Porque com conselhos prudentes tu podes fazer a guerra; e há vitória na multidão dos conselheiros.");
    b->dados[PROVERBIOS].capitulos[24].versos[7] = _("A sabedoria é alta demais para o insensato; ele não abre a sua boca na porta.");
    b->dados[PROVERBIOS].capitulos[24].versos[8] = _("Aquele que cuida em fazer o mal, mestre de maus intentos o chamarão.");
    b->dados[PROVERBIOS].capitulos[24].versos[9] = _("O desígnio do insensato é pecado; e abominável aos homens é o escarnecedor.");
    b->dados[PROVERBIOS].capitulos[24].versos[10] = _("Se enfraqueces no dia da angústia, a tua força é pequena.");
    b->dados[PROVERBIOS].capitulos[24].versos[11] = _("Livra os que estão sendo levados à morte, detém os que vão tropeçando para a matança.");
    b->dados[PROVERBIOS].capitulos[24].versos[12] = _("Se disseres: Eis que não o sabemos; porventura aquele que pesa os corações não o percebe? e aquele que guarda a tua vida não o sabe? e não retribuirá a cada um conforme a sua obra?");
    b->dados[PROVERBIOS].capitulos[24].versos[13] = _("Come mel, filho meu, porque é bom, e do favo de mel, que é doce ao teu paladar.");
    b->dados[PROVERBIOS].capitulos[24].versos[14] = _("Sabe que é assim a sabedoria para a tua alma: se a achares, haverá para ti recompensa, e não será malograda a tua esperança.");
    b->dados[PROVERBIOS].capitulos[24].versos[15] = _("Não te ponhas de emboscada, ó ímpio, contra a habitação do justo; nem assoles a sua pousada.");
    b->dados[PROVERBIOS].capitulos[24].versos[16] = _("Porque sete vezes cai o justo, e se levanta; mas os ímpios são derribados pela calamidade.");
    b->dados[PROVERBIOS].capitulos[24].versos[17] = _("Quando cair o teu inimigo, não te alegres, e quando tropeçar, não se regozije o teu coração;");
    b->dados[PROVERBIOS].capitulos[24].versos[18] = _("para que o Senhor não o veja, e isso seja mau aos seus olhos, e desvie dele, a sua ira.");
    b->dados[PROVERBIOS].capitulos[24].versos[19] = _("Não te aflijas por causa dos malfeitores; nem tenhas inveja dos ímpios;");
    b->dados[PROVERBIOS].capitulos[24].versos[20] = _("porque o maligno não tem futuro; e a lâmpada dos ímpios se apagará.");
    b->dados[PROVERBIOS].capitulos[24].versos[21] = _("Filho meu, teme ao Senhor, e ao rei; e não te entremetas com os que gostam de mudanças.");
    b->dados[PROVERBIOS].capitulos[24].versos[22] = _("Porque de repente se levantará a sua calamidade; e a ruína deles, quem a conhecerá?");
    b->dados[PROVERBIOS].capitulos[24].versos[23] = _("Também estes são provérbios dos sábios: Fazer acepção de pessoas no juízo não é bom.");
    b->dados[PROVERBIOS].capitulos[24].versos[24] = _("Aquele que disser ao ímpio: Justo és; os povos o amaldiçoarão, as nações o detestarão;");
    b->dados[PROVERBIOS].capitulos[24].versos[25] = _("mas para os que julgam retamente haverá delícias, e sobre eles virá copiosa bênção.");
    b->dados[PROVERBIOS].capitulos[24].versos[26] = _("O que responde com palavras retas beija os lábios.");
    b->dados[PROVERBIOS].capitulos[24].versos[27] = _("Prepara os teus trabalhos de fora, apronta bem o teu campo; e depois edifica a tua casa.");
    b->dados[PROVERBIOS].capitulos[24].versos[28] = _("Não sejas testemunha sem causa contra o teu próximo; e não enganes com os teus lábios.");
    b->dados[PROVERBIOS].capitulos[24].versos[29] = _("Não digas: Como ele me fez a mim, assim lhe farei a ele; pagarei a cada um segundo a sua obra.");
    b->dados[PROVERBIOS].capitulos[24].versos[30] = _("Passei junto ao campo do preguiçoso, e junto à vinha do homem falto de entendimento;");
    b->dados[PROVERBIOS].capitulos[24].versos[31] = _("e eis que tudo estava cheio de cardos, e a sua superfície coberta de urtigas, e o seu muro de pedra estava derrubado.");
    b->dados[PROVERBIOS].capitulos[24].versos[32] = _("O que tendo eu visto, o considerei; e, vendo-o, recebi instrução.");
    b->dados[PROVERBIOS].capitulos[24].versos[33] = _("Um pouco para dormir, um pouco para toscanejar, um pouco para cruzar os braços em repouso;");
    b->dados[PROVERBIOS].capitulos[24].versos[34] = _("assim sobrevirá a tua pobreza como um salteador, e a tua necessidade como um homem armado.");

    b->dados[PROVERBIOS].capitulos[25].versos[1] = _("Também estes são provérbios de Salomão, os quais transcreveram os homens de Ezequias, rei de Judá.");
    b->dados[PROVERBIOS].capitulos[25].versos[2] = _("A glória de Deus é encobrir as coisas; mas a glória dos reis é esquadrinhá-las.");
    b->dados[PROVERBIOS].capitulos[25].versos[3] = _("Como o céu na sua altura, e como a terra na sua profundidade, assim o coração dos reis é inescrutável.");
    b->dados[PROVERBIOS].capitulos[25].versos[4] = _("Tira da prata a escória, e sairá um vaso para o fundidor.");
    b->dados[PROVERBIOS].capitulos[25].versos[5] = _("Tira o ímpio da presença do rei, e o seu trono se firmará na justiça.");
    b->dados[PROVERBIOS].capitulos[25].versos[6] = _("Não reclames para ti honra na presença do rei, nem te ponhas no lugar dos grandes;");
    b->dados[PROVERBIOS].capitulos[25].versos[7] = _("porque melhor é que te digam: Sobe, para aqui; do que seres humilhado perante o príncipe.");
    b->dados[PROVERBIOS].capitulos[25].versos[8] = _("O que os teus olhos viram, não te apresses a revelar, para depois, ao fim, não saberes o que hás de fazer, podendo-te confundir o teu próximo.");
    b->dados[PROVERBIOS].capitulos[25].versos[9] = _("Pleiteia a tua causa com o teu próximo mesmo; e não reveles o segredo de outrem;");
    b->dados[PROVERBIOS].capitulos[25].versos[10] = _("para que não te desonre aquele que o ouvir, não se apartando de ti a infâmia.");
    b->dados[PROVERBIOS].capitulos[25].versos[11] = _("Como maçãs de ouro em salvas de prata, assim é a palavra dita a seu tempo.");
    b->dados[PROVERBIOS].capitulos[25].versos[12] = _("Como pendentes de ouro e gargantilhas de ouro puro, assim é o sábio repreensor para o ouvido obediente.");
    b->dados[PROVERBIOS].capitulos[25].versos[13] = _("Como o frescor de neve no tempo da sega, assim é o mensageiro fiel para com os que o enviam, porque refrigera o espírito dos seus senhores.");
    b->dados[PROVERBIOS].capitulos[25].versos[14] = _("como nuvens e ventos que não trazem chuva, assim é o homem que se gaba de dádivas que não fez.");
    b->dados[PROVERBIOS].capitulos[25].versos[15] = _("Pela longanimidade se persuade o príncipe, e a língua branda quebranta os ossos.");
    b->dados[PROVERBIOS].capitulos[25].versos[16] = _("Se achaste mel, come somente o que te basta, para que porventura não te fartes dele, e o venhas a vomitar.");
    b->dados[PROVERBIOS].capitulos[25].versos[17] = _("Põe raramente o teu pé na casa do teu próximo, para que não se enfade de ti, e te aborreça.");
    b->dados[PROVERBIOS].capitulos[25].versos[18] = _("Malho, e espada, e flecha aguda é o homem que levanta falso testemunho contra o seu próximo.");
    b->dados[PROVERBIOS].capitulos[25].versos[19] = _("Como dente quebrado, e pé deslocado, é a confiança no homem desleal, no dia da angústia.");
    b->dados[PROVERBIOS].capitulos[25].versos[20] = _("O que entoa canções ao coração aflito é como aquele que despe uma peça de roupa num dia de frio, e como vinagre sobre a chaga.");
    b->dados[PROVERBIOS].capitulos[25].versos[21] = _("Se o teu inimigo tiver fome, dá-lhe pão para comer, e se tiver sede, dá-lhe água para beber;");
    b->dados[PROVERBIOS].capitulos[25].versos[22] = _("porque assim lhe amontoarás brasas sobre a cabeça, e o Senhor te recompensará.");
    b->dados[PROVERBIOS].capitulos[25].versos[23] = _("O vento norte traz chuva, e a língua caluniadora, o rosto irado.");
    b->dados[PROVERBIOS].capitulos[25].versos[24] = _("Melhor é morar num canto do eirado, do que com a mulher rixosa numa casa ampla.");
    b->dados[PROVERBIOS].capitulos[25].versos[25] = _("Como água fresca para o homem sedento, tais são as boas-novas de terra remota.");
    b->dados[PROVERBIOS].capitulos[25].versos[26] = _("Como fonte turva, e manancial poluído, assim é o justo que cede lugar diante do ímpio.");
    b->dados[PROVERBIOS].capitulos[25].versos[27] = _("comer muito mel não é bom; não multipliques, pois, as palavras de lisonja.");
    b->dados[PROVERBIOS].capitulos[25].versos[28] = _("Como a cidade derribada, que não tem muros, assim é o homem que não pode conter o seu espírito.");

    b->dados[PROVERBIOS].capitulos[26].versos[1] = _("Como a neve no verão, e como a chuva no tempo da ceifa, assim não convém ao tolo a honra.");
    b->dados[PROVERBIOS].capitulos[26].versos[2] = _("Como o pássaro no seu vaguear, como a andorinha no seu voar, assim a maldição sem causa não encontra pouso.");
    b->dados[PROVERBIOS].capitulos[26].versos[3] = _("O açoite é para o cavalo, o freio para o jumento, e a vara para as costas dos tolos.");
    b->dados[PROVERBIOS].capitulos[26].versos[4] = _("Não respondas ao tolo segundo a sua estultícia, para que também não te faças semelhante a ele.");
    b->dados[PROVERBIOS].capitulos[26].versos[5] = _("Responde ao tolo segundo a sua estultícia, para que ele não seja sábio aos seus próprios olhos.");
    b->dados[PROVERBIOS].capitulos[26].versos[6] = _("Os pés decepa, e o dano bebe, quem manda mensagens pela mão dum tolo.");
    b->dados[PROVERBIOS].capitulos[26].versos[7] = _("As pernas do coxo pendem frouxas; assim é o provérbio na boca dos tolos.");
    b->dados[PROVERBIOS].capitulos[26].versos[8] = _("Como o que ata a pedra na funda, assim é aquele que dá honra ao tolo.");
    b->dados[PROVERBIOS].capitulos[26].versos[9] = _("Como o espinho que entra na mão do ébrio, assim é o provérbio na mão dos tolos.");
    b->dados[PROVERBIOS].capitulos[26].versos[10] = _("Como o flecheiro que fere a todos, assim é aquele que assalaria ao transeunte tolo, ou ao ébrio.");
    b->dados[PROVERBIOS].capitulos[26].versos[11] = _("Como o cão que torna ao seu vômito, assim é o tolo que reitera a sua estultícia.");
    b->dados[PROVERBIOS].capitulos[26].versos[12] = _("Vês um homem que é sábio a seus próprios olhos? Maior esperança há para o tolo do que para ele.");
    b->dados[PROVERBIOS].capitulos[26].versos[13] = _("Diz o preguiçoso: Um leão está no caminho; um leão está nas ruas.");
    b->dados[PROVERBIOS].capitulos[26].versos[14] = _("Como a porta se revolve nos seus gonzos, assim o faz o preguiçoso na sua cama.");
    b->dados[PROVERBIOS].capitulos[26].versos[15] = _("O preguiçoso esconde a sua mão no prato, e nem ao menos quer levá-la de novo à boca.");
    b->dados[PROVERBIOS].capitulos[26].versos[16] = _("Mais sábio é o preguiçoso a seus olhos do que sete homens que sabem responder bem.");
    b->dados[PROVERBIOS].capitulos[26].versos[17] = _("O que, passando, se mete em questão alheia é como aquele que toma um cão pelas orelhas.");
    b->dados[PROVERBIOS].capitulos[26].versos[18] = _("Como o louco que atira tições, flechas, e morte,");
    b->dados[PROVERBIOS].capitulos[26].versos[19] = _("assim é o homem que engana o seu próximo, e diz: Fiz isso por brincadeira.");
    b->dados[PROVERBIOS].capitulos[26].versos[20] = _("Faltando lenha, apaga-se o fogo; e não havendo difamador, cessa a contenda.");
    b->dados[PROVERBIOS].capitulos[26].versos[21] = _("Como o carvão para as brasas, e a lenha para o fogo, assim é o homem contencioso para acender rixas.");
    b->dados[PROVERBIOS].capitulos[26].versos[22] = _("As palavras do difamador são como bocados deliciosos, que descem ao íntimo do ventre.");
    b->dados[PROVERBIOS].capitulos[26].versos[23] = _("Como o vaso de barro coberto de escória de prata, assim são os lábios ardentes e o coração maligno.");
    b->dados[PROVERBIOS].capitulos[26].versos[24] = _("Aquele que odeia dissimula com os seus lábios; mas no seu interior entesoura o engano.");
    b->dados[PROVERBIOS].capitulos[26].versos[25] = _("Quando te suplicar com voz suave, não o creias; porque sete abominações há no teu coração.");
    b->dados[PROVERBIOS].capitulos[26].versos[26] = _("Ainda que o seu ódio se encubra com dissimulação, na congregação será revelada a sua malícia.");
    b->dados[PROVERBIOS].capitulos[26].versos[27] = _("O que faz uma cova cairá nela; e a pedra voltará sobre aquele que a revolve.");
    b->dados[PROVERBIOS].capitulos[26].versos[28] = _("A língua falsa odeia aqueles a quem ela tenha ferido; e a boca lisonjeira opera a ruína.");

    b->dados[PROVERBIOS].capitulos[27].versos[1] = _("Não te glories do dia de amanhã; porque não sabes o que produzirá o dia.");
    b->dados[PROVERBIOS].capitulos[27].versos[2] = _("Seja outro o que te louve, e não a tua boca; o estranho, e não os teus lábios.");
    b->dados[PROVERBIOS].capitulos[27].versos[3] = _("Pesada é a pedra, e a areia também; mas a ira do insensato é mais pesada do que elas ambas.");
    b->dados[PROVERBIOS].capitulos[27].versos[4] = _("Cruel é o furor, e impetuosa é a ira; mas quem pode resistir à inveja?");
    b->dados[PROVERBIOS].capitulos[27].versos[5] = _("Melhor é a repreensão aberta do que o amor encoberto.");
    b->dados[PROVERBIOS].capitulos[27].versos[6] = _("Fiéis são as feridas dum amigo; mas os beijos dum inimigo são enganosos.");
    b->dados[PROVERBIOS].capitulos[27].versos[7] = _("O que está farto despreza o favo de mel; mas para o faminto todo amargo é doce.");
    b->dados[PROVERBIOS].capitulos[27].versos[8] = _("Qual a ave que vagueia longe do seu ninho, tal é o homem que anda vagueando longe do seu lugar.");
    b->dados[PROVERBIOS].capitulos[27].versos[9] = _("O óleo e o perfume alegram o coração; assim é o doce conselho do homem para o seu amigo.");
    b->dados[PROVERBIOS].capitulos[27].versos[10] = _("Não abandones o teu amigo, nem o amigo de teu pai; nem entres na casa de teu irmão no dia de tua adversidade. Mais vale um vizinho que está perto do que um irmão que está longe.");
    b->dados[PROVERBIOS].capitulos[27].versos[11] = _("Sê sábio, filho meu, e alegra o meu coração, para que eu tenha o que responder àquele que me vituperar.");
    b->dados[PROVERBIOS].capitulos[27].versos[12] = _("O prudente vê o mal e se esconde; mas os insensatos passam adiante e sofrem a pena.");
    b->dados[PROVERBIOS].capitulos[27].versos[13] = _("Tira a roupa àquele que fica por fiador do estranho, e toma penhor daquele que se obriga por uma estrangeira.");
    b->dados[PROVERBIOS].capitulos[27].versos[14] = _("O que bendiz ao seu amigo em alta voz, levantando-se de madrugada, isso lhe será contado como maldição.");
    b->dados[PROVERBIOS].capitulos[27].versos[15] = _("A goteira contínua num dia chuvoso e a mulher rixosa são semelhantes;");
    b->dados[PROVERBIOS].capitulos[27].versos[16] = _("retê-la é reter o vento, ou segurar o óleo com a destra.");
    b->dados[PROVERBIOS].capitulos[27].versos[17] = _("Afia-se o ferro com o ferro; assim o homem afia o rosto do seu amigo.");
    b->dados[PROVERBIOS].capitulos[27].versos[18] = _("O que cuida da figueira comerá do fruto dela; e o que vela pelo seu senhor será honrado.");
    b->dados[PROVERBIOS].capitulos[27].versos[19] = _("Como na água o rosto corresponde ao rosto, assim o coração do homem ao homem.");
    b->dados[PROVERBIOS].capitulos[27].versos[20] = _("O Seol e o Abadom nunca se fartam, e os olhos do homem nunca se satisfazem.");
    b->dados[PROVERBIOS].capitulos[27].versos[21] = _("O crisol é para a prata, e o forno para o ouro, e o homem é provado pelos louvores que recebe.");
    b->dados[PROVERBIOS].capitulos[27].versos[22] = _("Ainda que pisasses o insensato no gral entre grãos pilados, contudo não se apartaria dele a sua estultícia.");
    b->dados[PROVERBIOS].capitulos[27].versos[23] = _("Procura conhecer o estado das tuas ovelhas; cuida bem dos teus rebanhos;");
    b->dados[PROVERBIOS].capitulos[27].versos[24] = _("porque as riquezas não duram para sempre; e duraria a coroa de geração em geração?");
    b->dados[PROVERBIOS].capitulos[27].versos[25] = _("Quando o feno é removido, e aparece a erva verde, e recolhem-se as ervas dos montes,");
    b->dados[PROVERBIOS].capitulos[27].versos[26] = _("os cordeiros te proverão de vestes, e os bodes, do preço do campo.");
    b->dados[PROVERBIOS].capitulos[27].versos[27] = _("E haverá bastante leite de cabras para o teu sustento, para o sustento da tua casa e das tuas criadas.");

    b->dados[PROVERBIOS].capitulos[28].versos[1] = _("Fogem os ímpios, sem que ninguém os persiga; mas os justos são ousados como o leão.");
    b->dados[PROVERBIOS].capitulos[28].versos[2] = _("Por causa da transgressão duma terra são muitos os seus príncipes; mas por virtude de homens prudentes e entendidos, ela subsistirá por longo tempo.");
    b->dados[PROVERBIOS].capitulos[28].versos[3] = _("O homem pobre que oprime os pobres, é como chuva impetuosa, que não deixa trigo nenhum.");
    b->dados[PROVERBIOS].capitulos[28].versos[4] = _("Os que abandonam a lei louvam os ímpios; mas os que guardam a lei pelejam contra eles.");
    b->dados[PROVERBIOS].capitulos[28].versos[5] = _("Os homens maus não entendem a justiça; mas os que buscam ao Senhor a entendem plenamente.");
    b->dados[PROVERBIOS].capitulos[28].versos[6] = _("Melhor é o pobre que anda na sua integridade, do que o rico perverso nos seus caminhos.");
    b->dados[PROVERBIOS].capitulos[28].versos[7] = _("O que guarda a lei é filho sábio; mas o companheiro dos comilões envergonha a seu pai.");
    b->dados[PROVERBIOS].capitulos[28].versos[8] = _("O que aumenta a sua riqueza com juros e usura, ajunta-a para o que se compadece do pobre.");
    b->dados[PROVERBIOS].capitulos[28].versos[9] = _("O que desvia os seus ouvidos de ouvir a lei, até a sua oração é abominável.");
    b->dados[PROVERBIOS].capitulos[28].versos[10] = _("O que faz com que os retos se desviem para um mau caminho, ele mesmo cairá na cova que abriu; mas os inocentes herdarão o bem.");
    b->dados[PROVERBIOS].capitulos[28].versos[11] = _("O homem rico é sábio aos seus próprios olhos; mas o pobre que tem entendimento o esquadrinha.");
    b->dados[PROVERBIOS].capitulos[28].versos[12] = _("Quando os justos triunfam há grande, glória; mas quando os ímpios sobem, escondem-se os homens.");
    b->dados[PROVERBIOS].capitulos[28].versos[13] = _("O que encobre as suas transgressões nunca prosperará; mas o que as confessa e deixa, alcançará misericórdia.");
    b->dados[PROVERBIOS].capitulos[28].versos[14] = _("Feliz é o homem que teme ao Senhor continuamente; mas o que endurece o seu coração virá a cair no mal.");
    b->dados[PROVERBIOS].capitulos[28].versos[15] = _("Como leão bramidor, e urso faminto, assim é o ímpio que domina sobre um povo pobre.");
    b->dados[PROVERBIOS].capitulos[28].versos[16] = _("O príncipe falto de entendimento é também opressor cruel; mas o que aborrece a avareza prolongará os seus dias.");
    b->dados[PROVERBIOS].capitulos[28].versos[17] = _("O homem culpado do sangue de qualquer pessoa será fugitivo até a morte; ninguém o ajude.");
    b->dados[PROVERBIOS].capitulos[28].versos[18] = _("O que anda retamente salvar-se-á; mas o perverso em seus caminhos cairá de repente.");
    b->dados[PROVERBIOS].capitulos[28].versos[19] = _("O que lavra a sua terra se fartará de pão; mas o que segue os ociosos se encherá de pobreza.");
    b->dados[PROVERBIOS].capitulos[28].versos[20] = _("O homem fiel gozará de abundantes bênçãos; mas o que se apressa a enriquecer não ficará impune.");
    b->dados[PROVERBIOS].capitulos[28].versos[21] = _("Fazer acepção de pessoas não é bom; mas até por um bocado de pão prevaricará o homem.");
    b->dados[PROVERBIOS].capitulos[28].versos[22] = _("Aquele que é cobiçoso corre atrás das riquezas; e não sabe que há de vir sobre ele a penúria.");
    b->dados[PROVERBIOS].capitulos[28].versos[23] = _("O que repreende a um homem achará depois mais favor do que aquele que lisonjeia com a língua.");
    b->dados[PROVERBIOS].capitulos[28].versos[24] = _("O que rouba a seu pai, ou a sua mãe, e diz: Isso não é transgressão; esse é companheiro do destruidor.");
    b->dados[PROVERBIOS].capitulos[28].versos[25] = _("O cobiçoso levanta contendas; mas o que confia no senhor prosperará.");
    b->dados[PROVERBIOS].capitulos[28].versos[26] = _("O que confia no seu próprio coração é insensato; mas o que anda sabiamente será livre.");
    b->dados[PROVERBIOS].capitulos[28].versos[27] = _("O que dá ao pobre não terá falta; mas o que esconde os seus olhos terá muitas maldições.");
    b->dados[PROVERBIOS].capitulos[28].versos[28] = _("Quando os ímpios sobem, escondem-se os homens; mas quando eles perecem, multiplicam-se os justos.");

    b->dados[PROVERBIOS].capitulos[29].versos[1] = _("Aquele que, sendo muitas vezes repreendido, endurece a cerviz, será quebrantado de repente sem que haja cura.");
    b->dados[PROVERBIOS].capitulos[29].versos[2] = _("Quando os justos governam, alegra-se o povo; mas quando o ímpio domina, o povo geme.");
    b->dados[PROVERBIOS].capitulos[29].versos[3] = _("O que ama a sabedoria alegra a seu pai; mas o companheiro de prostitutas desperdiça a sua riqueza.");
    b->dados[PROVERBIOS].capitulos[29].versos[4] = _("O rei pela justiça estabelece a terra; mas o que exige presentes a transtorna.");
    b->dados[PROVERBIOS].capitulos[29].versos[5] = _("O homem que lisonjeia a seu próximo arma-lhe uma rede aos passos.");
    b->dados[PROVERBIOS].capitulos[29].versos[6] = _("Na transgressão do homem mau há laço; mas o justo canta e se regozija.");
    b->dados[PROVERBIOS].capitulos[29].versos[7] = _("O justo toma conhecimento da causa dos pobres; mas o ímpio não tem entendimento para a conhecer.");
    b->dados[PROVERBIOS].capitulos[29].versos[8] = _("Os escarnecedores abrasam a cidade; mas os sábios desviam a ira.");
    b->dados[PROVERBIOS].capitulos[29].versos[9] = _("O sábio que pleiteia com o insensato, quer este se agaste quer se ria, não terá descanso.");
    b->dados[PROVERBIOS].capitulos[29].versos[10] = _("Os homens sanguinários odeiam o íntegro; mas os retos procuram o seu bem.");
    b->dados[PROVERBIOS].capitulos[29].versos[11] = _("O tolo derrama toda a sua ira; mas o sábio a reprime e aplaca.");
    b->dados[PROVERBIOS].capitulos[29].versos[12] = _("O governador que dá atenção às palavras mentirosas achará que todos os seus servos são ímpios.");
    b->dados[PROVERBIOS].capitulos[29].versos[13] = _("O pobre e o opressor se encontram; o Senhor alumia os olhos de ambos.");
    b->dados[PROVERBIOS].capitulos[29].versos[14] = _("Se o rei julgar os pobres com eqüidade, o seu trono será estabelecido para sempre.");
    b->dados[PROVERBIOS].capitulos[29].versos[15] = _("A vara e a repreensão dão sabedoria; mas a criança entregue a si mesma envergonha a sua mãe.");
    b->dados[PROVERBIOS].capitulos[29].versos[16] = _("Quando os ímpios se multiplicam, multiplicam-se as transgressões; mas os justos verão a queda deles.");
    b->dados[PROVERBIOS].capitulos[29].versos[17] = _("Corrige a teu filho, e ele te dará descanso; sim, deleitará o teu coração.");
    b->dados[PROVERBIOS].capitulos[29].versos[18] = _("Onde não há profecia, o povo se corrompe; mas o que guarda a lei esse é bem-aventurado.");
    b->dados[PROVERBIOS].capitulos[29].versos[19] = _("O servo não se emendará com palavras; porque, ainda que entenda, não atenderá.");
    b->dados[PROVERBIOS].capitulos[29].versos[20] = _("Vês um homem precipitado nas suas palavras? Maior esperança há para o tolo do que para ele.");
    b->dados[PROVERBIOS].capitulos[29].versos[21] = _("Aquele que cria delicadamente o seu servo desde a meninice, no fim tê-lo-á por herdeiro.");
    b->dados[PROVERBIOS].capitulos[29].versos[22] = _("O homem iracundo levanta contendas, e o furioso multiplica as transgressões.");
    b->dados[PROVERBIOS].capitulos[29].versos[23] = _("A soberba do homem o abaterá; mas o humilde de espírito obterá honra.");
    b->dados[PROVERBIOS].capitulos[29].versos[24] = _("O que é sócio do ladrão odeia a sua própria alma; sendo ajuramentado, nada denuncia.");
    b->dados[PROVERBIOS].capitulos[29].versos[25] = _("O receio do homem lhe arma laços; mas o que confia no Senhor está seguro.");
    b->dados[PROVERBIOS].capitulos[29].versos[26] = _("Muitos buscam o favor do príncipe; mas é do Senhor que o homem recebe a justiça.");
    b->dados[PROVERBIOS].capitulos[29].versos[27] = _("O ímpio é abominação para os justos; e o que é reto no seu caminho é abominação para o ímpio.");

    b->dados[PROVERBIOS].capitulos[30].versos[1] = _("Palavras de Agur, filho de Jaqué de Massá. Diz o homem a Itiel, e a Ucal:");
    b->dados[PROVERBIOS].capitulos[30].versos[2] = _("Na verdade que eu sou mais estúpido do que ninguém; não tenho o entendimento do homem;");
    b->dados[PROVERBIOS].capitulos[30].versos[3] = _("não aprendi a sabedoria, nem tenho o conhecimento do Santo.");
    b->dados[PROVERBIOS].capitulos[30].versos[4] = _("Quem subiu ao céu e desceu? quem encerrou os ventos nos seus punhos? mas amarrou as águas no seu manto? quem estabeleceu todas as extremidades da terra? qual é o seu nome, e qual é o nome de seu filho? Certamente o sabes!");
    b->dados[PROVERBIOS].capitulos[30].versos[5] = _("Toda palavra de Deus é pura; ele é um escudo para os que nele confiam.");
    b->dados[PROVERBIOS].capitulos[30].versos[6] = _("Nada acrescentes às suas palavras, para que ele não te repreenda e tu sejas achado mentiroso.");
    b->dados[PROVERBIOS].capitulos[30].versos[7] = _("Duas coisas te peço; não mas negues, antes que morra:");
    b->dados[PROVERBIOS].capitulos[30].versos[8] = _("Alonga de mim a falsidade e a mentira; não me dês nem a pobreza nem a riqueza: dá-me só o pão que me é necessário;");
    b->dados[PROVERBIOS].capitulos[30].versos[9] = _("para que eu de farto não te negue, e diga: Quem é o Senhor? ou, empobrecendo, não venha a furtar, e profane o nome de Deus.");
    b->dados[PROVERBIOS].capitulos[30].versos[10] = _("Não calunies o servo diante de seu senhor, para que ele não te amaldiçoe e fiques tu culpado.");
    b->dados[PROVERBIOS].capitulos[30].versos[11] = _("Há gente que amaldiçoa a seu pai, e que não bendiz a sua mãe.");
    b->dados[PROVERBIOS].capitulos[30].versos[12] = _("Há gente que é pura aos seus olhos, e contudo nunca foi lavada da sua imundícia.");
    b->dados[PROVERBIOS].capitulos[30].versos[13] = _("Há gente cujos olhos são altivos, e cujas pálpebras são levantadas para cima.");
    b->dados[PROVERBIOS].capitulos[30].versos[14] = _("Há gente cujos dentes são como espadas; e cujos queixais são como facas, para devorarem da terra os aflitos, e os necessitados dentre os homens.");
    b->dados[PROVERBIOS].capitulos[30].versos[15] = _("A sanguessuga tem duas filhas, a saber: Dá, Dá. Há três coisas que nunca se fartam; sim, quatro que nunca dizem: Basta;");
    b->dados[PROVERBIOS].capitulos[30].versos[16] = _("o Seol, a madre estéril, a terra que não se farta d'água, e o fogo que nunca diz: Basta.");
    b->dados[PROVERBIOS].capitulos[30].versos[17] = _("Os olhos que zombam do pai, ou desprezam a obediência à mãe, serão arrancados pelos corvos do vale e devorados pelos filhos da águia.");
    b->dados[PROVERBIOS].capitulos[30].versos[18] = _("Há três coisas que são maravilhosas demais para mim, sim, há quatro que não conheço:");
    b->dados[PROVERBIOS].capitulos[30].versos[19] = _("o caminho da águia no ar, o caminho da cobra na penha, o caminho do navio no meio do mar, e o caminho do homem com uma virgem.");
    b->dados[PROVERBIOS].capitulos[30].versos[20] = _("Tal é o caminho da mulher adúltera: ela come, e limpa a sua boca, e diz: não pratiquei iniqüidade.");
    b->dados[PROVERBIOS].capitulos[30].versos[21] = _("Por três coisas estremece a terra, sim, há quatro que não pode suportar:");
    b->dados[PROVERBIOS].capitulos[30].versos[22] = _("o escravo quando reina; o tolo quando se farta de comer;");
    b->dados[PROVERBIOS].capitulos[30].versos[23] = _("a mulher desdenhada quando se casa; e a serva quando fica herdeira da sua senhora.");
    b->dados[PROVERBIOS].capitulos[30].versos[24] = _("Quatro coisas há na terra que são pequenas, entretanto são extremamente sábias;");
    b->dados[PROVERBIOS].capitulos[30].versos[25] = _("as formigas são um povo sem força, todavia no verão preparam a sua comida;");
    b->dados[PROVERBIOS].capitulos[30].versos[26] = _("os querogrilos são um povo débil, contudo fazem a sua casa nas rochas;");
    b->dados[PROVERBIOS].capitulos[30].versos[27] = _("os gafanhotos não têm rei, contudo marcham todos enfileirados;");
    b->dados[PROVERBIOS].capitulos[30].versos[28] = _("a lagartixa apanha-se com as mãos, contudo anda nos palácios dos reis.");
    b->dados[PROVERBIOS].capitulos[30].versos[29] = _("Há três que andam com elegância, sim, quatro que se movem airosamente:");
    b->dados[PROVERBIOS].capitulos[30].versos[30] = _("o leão, que é o mais forte entre os animais, e que não se desvia diante de ninguém;");
    b->dados[PROVERBIOS].capitulos[30].versos[31] = _("o galo emproado, o bode, e o rei à frente do seu povo.");
    b->dados[PROVERBIOS].capitulos[30].versos[32] = _("Se procedeste loucamente em te elevares, ou se maquinaste o mal, põe a mão sobre a boca.");
    b->dados[PROVERBIOS].capitulos[30].versos[33] = _("Como o espremer do leite produz queijo verde, e o espremer do nariz produz sangue, assim o espremer da ira produz contenda.");

    b->dados[PROVERBIOS].capitulos[31].versos[1] = _("As palavras do rei Lemuel, rei de Massá, que lhe ensinou sua mãe.");
    b->dados[PROVERBIOS].capitulos[31].versos[2] = _("Que te direi, filho meu? e que te direi, ó filho do meu ventre? e que te direi, ó filho dos meus votos?");
    b->dados[PROVERBIOS].capitulos[31].versos[3] = _("Não dês às mulheres a tua força, nem os teus caminhos às que destroem os reis.");
    b->dados[PROVERBIOS].capitulos[31].versos[4] = _("Não é dos reis, ó Lemuel, não é dos reis beber vinho, nem dos príncipes desejar bebida forte;");
    b->dados[PROVERBIOS].capitulos[31].versos[5] = _("para que não bebam, e se esqueçam da lei, e pervertam o direito de quem anda aflito.");
    b->dados[PROVERBIOS].capitulos[31].versos[6] = _("Dai bebida forte ao que está para perecer, e o vinho ao que está em amargura de espírito.");
    b->dados[PROVERBIOS].capitulos[31].versos[7] = _("Bebam e se esqueçam da sua pobreza, e da sua miséria não se lembrem mais.");
    b->dados[PROVERBIOS].capitulos[31].versos[8] = _("Abre a tua boca a favor do mudo, a favor do direito de todos os desamparados.");
    b->dados[PROVERBIOS].capitulos[31].versos[9] = _("Abre a tua boca; julga retamente, e faze justiça aos pobres e aos necessitados.");
    b->dados[PROVERBIOS].capitulos[31].versos[10] = _("Álefe. Mulher virtuosa, quem a pode achar? Pois o seu valor muito excede ao de jóias preciosas.");
    b->dados[PROVERBIOS].capitulos[31].versos[11] = _("Bete. O coração do seu marido confia nela, e não lhe haverá falta de lucro.");
    b->dados[PROVERBIOS].capitulos[31].versos[12] = _("Guímel. Ela lhe faz bem, e não mal, todos os dias da sua vida.");
    b->dados[PROVERBIOS].capitulos[31].versos[13] = _("Dálete. Ela busca lã e linho, e trabalha de boa vontade com as mãos.");
    b->dados[PROVERBIOS].capitulos[31].versos[14] = _("Hê. É como os navios do negociante; de longe traz o seu pão.");
    b->dados[PROVERBIOS].capitulos[31].versos[15] = _("Vave. E quando ainda está escuro, ela se levanta, e dá mantimento à sua casa, e a tarefa às suas servas.");
    b->dados[PROVERBIOS].capitulos[31].versos[16] = _("Zaine. Considera um campo, e compra-o; planta uma vinha com o fruto de suas mãos.");
    b->dados[PROVERBIOS].capitulos[31].versos[17] = _("Hete. Cinge os seus lombos de força, e fortalece os seus braços.");
    b->dados[PROVERBIOS].capitulos[31].versos[18] = _("Tete. Prova e vê que é boa a sua mercadoria; e a sua lâmpada não se apaga de noite.");
    b->dados[PROVERBIOS].capitulos[31].versos[19] = _("Iode. Estende as mãos ao fuso, e as suas mãos pegam na roca.");
    b->dados[PROVERBIOS].capitulos[31].versos[20] = _("Cafe. Abre a mão para o pobre; sim, ao necessitado estende as suas mãos.");
    b->dados[PROVERBIOS].capitulos[31].versos[21] = _("Lâmede. Não tem medo da neve pela sua família; pois todos os da sua casa estão vestidos de escarlate.");
    b->dados[PROVERBIOS].capitulos[31].versos[22] = _("Meme. Faz para si cobertas; de linho fino e de púrpura é o seu vestido.");
    b->dados[PROVERBIOS].capitulos[31].versos[23] = _("Nune. Conhece-se o seu marido nas portas, quando se assenta entre os anciãos da terra.");
    b->dados[PROVERBIOS].capitulos[31].versos[24] = _("Sâmerue. Faz vestidos de linho, e vende-os, e entrega cintas aos mercadores.");
    b->dados[PROVERBIOS].capitulos[31].versos[25] = _("Aine. A força e a dignidade são os seus vestidos; e ri-se do tempo vindouro.");
    b->dados[PROVERBIOS].capitulos[31].versos[26] = _("Pê. Abre a sua boca com sabedoria, e o ensino da benevolência está na sua língua.");
    b->dados[PROVERBIOS].capitulos[31].versos[27] = _("Tsadê. Olha pelo governo de sua casa, e não come o pão da preguiça.");
    b->dados[PROVERBIOS].capitulos[31].versos[28] = _("Côfe. Levantam-se seus filhos, e lhe chamam bem-aventurada, como também seu marido, que a louva, dizendo:");
    b->dados[PROVERBIOS].capitulos[31].versos[29] = _("Reche. Muitas mulheres têm procedido virtuosamente, mas tu a todas sobrepujas.");
    b->dados[PROVERBIOS].capitulos[31].versos[30] = _("Chine. Enganosa é a graça, e vã é a formosura; mas a mulher que teme ao Senhor, essa será louvada.");
    b->dados[PROVERBIOS].capitulos[31].versos[31] = _("Tau. Dai-lhe do fruto das suas mãos, e louvem-na nas portas as suas obras.");

}
